// ============================================================================
// admin router — /api/admin/marketing/*  (caller has already run isAdmin())
// ============================================================================
// Returns a Response for a marketing route, or null if the path is NOT a
// marketing route (so worker.js's admin-block 404 still fires).

async function handleAdminMarketing(req, env, url) {
  const path = url.pathname.replace(/^\/api\/admin\/marketing/, "");
  const method = req.method;
  if (!env.DB) return json({ error: "marketing database not provisioned yet" }, 503);
  let mm;

  // ---- CONTACTS (marketing view: consent + tags; create/edit lives in CRM tab) ----
  if (path === "/contacts" && method === "GET") {
    const q = clean(url.searchParams.get("q"), 80);
    const tag = clean(url.searchParams.get("tag"), 40).toLowerCase();
    const limit = Math.min(Number(url.searchParams.get("limit") || 300), 1000);
    let sql = "SELECT * FROM contacts WHERE 1=1";
    const binds = [];
    if (q) { sql += " AND (name LIKE ? OR phone LIKE ? OR email LIKE ?)"; const l = `%${q}%`; binds.push(l, l, l); }
    if (tag) { sql += " AND instr(',' || lower(tags) || ',', ?) > 0"; binds.push(`,${tag},`); }
    sql += " ORDER BY created DESC LIMIT ?";
    binds.push(limit);
    const { results } = await db(env).prepare(sql).bind(...binds).all();
    return json({ contacts: (results || []).map((c) => ({ ...c, tags: tagList(c.tags) })) });
  }

  // Create/edit contacts is owned by the CRM (/api/admin/crm/contacts); the
  // marketing UI links to it. This is a NARROW consent+tags PATCH so the
  // Contacts tab can toggle marketing consent without leaving the tab.
  if ((mm = path.match(/^\/contacts\/([0-9a-f-]{36})\/marketing$/)) && method === "PATCH") {
    const id = mm[1];
    const existing = await getContact(env, id);
    if (!existing) return json({ error: "not found" }, 404);
    const b = await parseBody(req);
    if (!b) return json({ error: "bad json" }, 400);
    const consentSms = b.consent_sms !== undefined ? (b.consent_sms ? 1 : 0) : existing.consent_sms;
    const consentEmail = b.consent_email !== undefined ? (b.consent_email ? 1 : 0) : existing.consent_email;
    const tags = b.tags !== undefined ? tagsToCsv(b.tags) : existing.tags;
    await db(env).prepare("UPDATE contacts SET consent_sms=?, consent_email=?, tags=? WHERE id=?")
      .bind(consentSms, consentEmail, tags, id).run();
    // Opting a contact back IN clears any matching suppression so future sends reach them.
    if (consentSms && !existing.consent_sms && existing.phone) await removeSuppression(env, existing.phone, "sms");
    if (consentEmail && !existing.consent_email && existing.email) await removeSuppression(env, existing.email, "email");
    return json({ ok: true });
  }

  // ---- CSV IMPORT (paste or file body text) ----
  // Body: { csv: "name,phone,email,tags\n...", consent_sms:false, consent_email:false }
  // Consent defaults OFF (per brief: "consent flags off -> ask"). Merges by
  // phone/email into the shared contacts table; unions tags; never downgrades
  // an existing opt-in.
  if (path === "/contacts/import-csv" && method === "POST") {
    const b = await parseBody(req);
    if (!b || !b.csv) return json({ error: "body.csv required" }, 400);
    const rows = parseCsv(clean(b.csv, 500000));
    if (rows.length < 1) return json({ error: "no rows" }, 422);
    const header = rows[0].map((h) => clean(h, 40).toLowerCase());
    const idx = (names) => { for (const n of names) { const i = header.indexOf(n); if (i >= 0) return i; } return -1; };
    const cName = idx(["name", "full name", "fullname", "contact"]);
    const cPhone = idx(["phone", "mobile", "cell", "phone number"]);
    const cEmail = idx(["email", "e-mail", "email address"]);
    const cTags = idx(["tags", "tag", "labels"]);
    const cNotes = idx(["notes", "note"]);
    const hasHeader = cName >= 0 || cPhone >= 0 || cEmail >= 0;
    const start = hasHeader ? 1 : 0;
    const consentSms = b.consent_sms === true ? 1 : 0;
    const consentEmail = b.consent_email === true ? 1 : 0;

    let imported = 0, updated = 0, skipped = 0;
    const errors = [];
    for (let i = start; i < rows.length; i++) {
      const r = rows[i];
      if (!r || r.every((x) => !clean(x))) continue;
      const rec = {
        name: cName >= 0 ? r[cName] : r[0],
        phone: cPhone >= 0 ? r[cPhone] : (!hasHeader ? r[1] : ""),
        email: cEmail >= 0 ? r[cEmail] : (!hasHeader ? r[2] : ""),
        tags: cTags >= 0 ? r[cTags] : "",
        notes: cNotes >= 0 ? r[cNotes] : "",
      };
      const phone = normPhone(rec.phone);
      const email = normEmail(rec.email);
      if (!phone && !email) { skipped++; continue; }
      try {
        const outcome = await upsertMarketingContact(env, {
          name: rec.name, phone, email, tags: rec.tags, notes: rec.notes,
          consent_sms: consentSms, consent_email: consentEmail, source: "csv",
        });
        if (outcome === "created") imported++; else updated++;
      } catch (e) {
        skipped++; if (errors.length < 20) errors.push(`row ${i + 1}: ${String(e).slice(0, 80)}`);
      }
    }
    return json({ ok: true, imported, updated, skipped, errors });
  }

  // ---- IMPORT FROM LEAD INBOX (KV lead:*) ----
  // Consent OFF by default per brief. Idempotent via upsert on phone/email.
  if (path === "/contacts/import-leads" && method === "POST") {
    if (!env.SITE) return json({ error: "lead inbox (KV) not configured" }, 503);
    const b = (await parseBody(req)) || {};
    const consentSms = b.consent_sms === true ? 1 : 0;
    const consentEmail = b.consent_email === true ? 1 : 0;
    const list = await env.SITE.list({ prefix: "lead:", limit: 1000 });
    let imported = 0, updated = 0, skipped = 0;
    for (const k of list.keys) {
      const v = await env.SITE.get(k.name);
      if (!v) continue;
      let lead; try { lead = JSON.parse(v); } catch { continue; }
      const phone = normPhone(lead.phone);
      const email = normEmail(lead.email);
      if (!phone && !email) { skipped++; continue; }
      const outcome = await upsertMarketingContact(env, {
        name: lead.name, phone, email,
        notes: lead.message ? `Lead form: ${clean(lead.message, 500)}` : "",
        tags: "lead", consent_sms: consentSms, consent_email: consentEmail, source: "site-lead",
      });
      if (outcome === "created") imported++; else updated++;
    }
    return json({ ok: true, imported, updated, skipped, total: list.keys.length });
  }

  // ---- SUPPRESSIONS ----
  if (path === "/suppressions" && method === "GET") {
    const { results } = await db(env).prepare("SELECT * FROM suppressions ORDER BY ts DESC LIMIT 500").all();
    return json({ suppressions: results || [] });
  }
  if (path === "/suppressions" && method === "POST") {
    const b = await parseBody(req);
    if (!b) return json({ error: "bad json" }, 400);
    const channel = b.channel === "email" ? "email" : "sms";
    const value = channel === "sms" ? normPhone(b.value) : normEmail(b.value);
    if (!value) return json({ error: "invalid address" }, 422);
    await addSuppression(env, value, channel, clean(b.reason, 40) || "manual");
    return json({ ok: true });
  }
  if (path === "/suppressions" && method === "DELETE") {
    const b = await parseBody(req);
    if (!b) return json({ error: "bad json" }, 400);
    const channel = b.channel === "email" ? "email" : "sms";
    const value = channel === "sms" ? normPhone(b.value) : normEmail(b.value);
    if (!value) return json({ error: "invalid address" }, 422);
    await removeSuppression(env, value, channel);
    return json({ ok: true });
  }

  // ---- LIVE RECIPIENT COUNT ----
  if (path === "/recipients/count" && method === "GET") {
    const channel = url.searchParams.get("channel") === "email" ? "email" : "sms";
    const tag = clean(url.searchParams.get("tag"), 200);
    const count = await countRecipients(env, channel, tag);
    return json({ count, channel, tag });
  }

  // ---- CAMPAIGNS ----
  if (path === "/campaigns" && method === "GET") {
    const { results } = await db(env).prepare("SELECT * FROM campaigns ORDER BY created DESC LIMIT 200").all();
    const campaigns = [];
    for (const c of results || []) campaigns.push({ ...c, stats: await campaignStats(env, c.id) });
    return json({ campaigns });
  }

  if (path === "/campaigns" && method === "POST") {
    const b = await parseBody(req);
    if (!b) return json({ error: "bad json" }, 400);
    const channel = b.channel === "email" ? "email" : "sms";
    const name = clean(b.name, 120);
    const body = clean(b.body, 4000);
    if (!name) return json({ error: "name required" }, 422);
    if (!body) return json({ error: "body required" }, 422);
    if (channel === "email" && !clean(b.subject, 200)) return json({ error: "subject required for email" }, 422);
    let status = "draft", scheduledAt = null;
    if (b.scheduled_at) {
      const sa = new Date(b.scheduled_at).getTime();
      if (!Number.isFinite(sa)) return json({ error: "bad scheduled_at" }, 422);
      scheduledAt = new Date(sa).toISOString();
      status = "scheduled";
    }
    const id = uuid();
    const tagFilter = tagsToCsv(b.tag_filter);
    await db(env).prepare(
      `INSERT INTO campaigns (id,channel,name,subject,body,tag_filter,status,scheduled_at,created)
       VALUES (?,?,?,?,?,?,?,?,?)`
    ).bind(id, channel, name, clean(b.subject, 200), body, tagFilter, status, scheduledAt, nowIso()).run();
    // Return the live recipient count so the composer can preview immediately.
    const recipient_count = await countRecipients(env, channel, tagFilter);
    return json({ ok: true, id, status, recipient_count }, 201);
  }

  if ((mm = path.match(/^\/campaigns\/([0-9a-f-]{36})$/)) && method === "GET") {
    const c = await db(env).prepare("SELECT * FROM campaigns WHERE id=?").bind(mm[1]).first();
    if (!c) return json({ error: "not found" }, 404);
    return json({ ...c, stats: await campaignStats(env, c.id) });
  }
  if ((mm = path.match(/^\/campaigns\/([0-9a-f-]{36})$/)) && method === "PUT") {
    const id = mm[1];
    const c = await db(env).prepare("SELECT * FROM campaigns WHERE id=?").bind(id).first();
    if (!c) return json({ error: "not found" }, 404);
    if (c.status === "sending" || c.status === "sent") return json({ error: "campaign already sending/sent" }, 409);
    const b = await parseBody(req);
    if (!b) return json({ error: "bad json" }, 400);
    await db(env).prepare(
      "UPDATE campaigns SET name=?, subject=?, body=?, tag_filter=? WHERE id=?"
    ).bind(
      b.name !== undefined ? clean(b.name, 120) : c.name,
      b.subject !== undefined ? clean(b.subject, 200) : c.subject,
      b.body !== undefined ? clean(b.body, 4000) : c.body,
      b.tag_filter !== undefined ? tagsToCsv(b.tag_filter) : c.tag_filter,
      id
    ).run();
    return json({ ok: true });
  }
  if ((mm = path.match(/^\/campaigns\/([0-9a-f-]{36})$/)) && method === "DELETE") {
    const id = mm[1];
    await db(env).prepare("DELETE FROM sends WHERE campaign_id=?").bind(id).run();
    await db(env).prepare("DELETE FROM campaigns WHERE id=?").bind(id).run();
    return json({ ok: true });
  }

  // ---- SEND NOW (typed "SEND" confirm + expected_count drift guard) ----
  if ((mm = path.match(/^\/campaigns\/([0-9a-f-]{36})\/send$/)) && method === "POST") {
    const id = mm[1];
    const c = await db(env).prepare("SELECT * FROM campaigns WHERE id=?").bind(id).first();
    if (!c) return json({ error: "not found" }, 404);
    if (c.status === "sending" || c.status === "sent") return json({ error: "already sending/sent" }, 409);
    const b = await parseBody(req);
    if (!b) return json({ error: "bad json" }, 400);
    if (clean(b.confirm) !== "SEND") return json({ error: "type SEND to confirm" }, 400);

    const actual = await countRecipients(env, c.channel, c.tag_filter);
    // Guard against a stale UI count: the list drifted since the operator looked.
    if (b.expected_count !== undefined && Number(b.expected_count) !== actual) {
      return json({ error: "recipient count changed", actual }, 409);
    }
    if (actual === 0) return json({ error: "no eligible recipients" }, 422);

    await db(env).prepare("UPDATE campaigns SET status='sending', scheduled_at=NULL WHERE id=?").bind(id).run();
    const queued = await enqueueCampaign(env, c);
    // Kick one immediate chunk so the operator sees movement (SMS still respects
    // quiet hours inside processQueue; out-of-window rows stay queued for cron).
    const processed = await processQueue(env, Number(env.SEND_CHUNK || 50));
    await finalizeCampaigns(env);
    return json({ ok: true, queued, processed, recipients: actual });
  }

  // ---- SCHEDULE ----
  if ((mm = path.match(/^\/campaigns\/([0-9a-f-]{36})\/schedule$/)) && method === "POST") {
    const id = mm[1];
    const c = await db(env).prepare("SELECT * FROM campaigns WHERE id=?").bind(id).first();
    if (!c) return json({ error: "not found" }, 404);
    if (c.status === "sending" || c.status === "sent") return json({ error: "already sending/sent" }, 409);
    const b = await parseBody(req);
    if (!b) return json({ error: "bad json" }, 400);
    const sa = new Date(b.scheduled_at).getTime();
    if (!Number.isFinite(sa)) return json({ error: "bad scheduled_at" }, 422);
    if (sa < Date.now() - 60000) return json({ error: "scheduled time is in the past" }, 422);
    await db(env).prepare("UPDATE campaigns SET status='scheduled', scheduled_at=? WHERE id=?")
      .bind(new Date(sa).toISOString(), id).run();
    return json({ ok: true, scheduled_at: new Date(sa).toISOString() });
  }

  // ---- PAUSE / RESUME ----
  if ((mm = path.match(/^\/campaigns\/([0-9a-f-]{36})\/pause$/)) && method === "POST") {
    await db(env).prepare("UPDATE campaigns SET status='paused' WHERE id=? AND status IN ('sending','scheduled')").bind(mm[1]).run();
    return json({ ok: true });
  }
  if ((mm = path.match(/^\/campaigns\/([0-9a-f-]{36})\/resume$/)) && method === "POST") {
    const id = mm[1];
    const c = await db(env).prepare("SELECT * FROM campaigns WHERE id=?").bind(id).first();
    if (!c || c.status !== "paused") return json({ error: "not paused" }, 409);
    const q = await db(env).prepare("SELECT COUNT(*) AS n FROM sends WHERE campaign_id=? AND status='queued'").bind(id).first();
    const next = q && q.n > 0 ? "sending" : "draft";
    await db(env).prepare("UPDATE campaigns SET status=? WHERE id=?").bind(next, id).run();
    return json({ ok: true, status: next });
  }

  // ---- TEST SEND (to Adrian only; never touches the queue) ----
  if (path === "/test-send" && method === "POST") {
    const b = await parseBody(req);
    if (!b) return json({ error: "bad json" }, 400);
    const channel = b.channel === "email" ? "email" : "sms";
    const to = channel === "sms" ? normPhone(b.to) : normEmail(b.to);
    if (!to) return json({ error: "invalid test address" }, 422);
    const sample = { name: clean(b.sample_name, 80) || "Adrian" };
    if (channel === "sms") {
      const out = withStopNotice(mergeBody(b.body, sample));
      const res = await sendSmsMessage(env, to, out);
      return res.ok ? json({ ok: true, id: res.id, demo: !!res.demo }) : json({ error: res.error }, 502);
    }
    const token = await signUnsub(env, to, "email");
    const unsubUrl = `${publicBase(env)}/u/${token}`;
    const res = await sendEmailMessage(env, to, clean(b.subject, 200) || "Test — Adrian Cortez", mergeBody(b.body, sample), unsubUrl);
    return res.ok ? json({ ok: true, id: res.id, demo: !!res.demo }) : json({ error: res.error }, 502);
  }

  return null; // not a marketing route — let worker.js's admin 404 fire
}

// Upsert into the shared contacts table by natural key (phone, then email).
// Unions tags; ratchets consent UP only (never silently downgrades an existing
// opt-in). Preserves CRM-only fields (stage/next_followup) on existing rows.
// Returns "created" | "updated".
async function upsertMarketingContact(env, input) {
  const phone = input.phone || "";
  const email = input.email || "";
  let existing = null;
  if (phone) existing = await db(env).prepare("SELECT * FROM contacts WHERE phone = ? LIMIT 1").bind(phone).first();
  if (!existing && email) existing = await db(env).prepare("SELECT * FROM contacts WHERE email = ? LIMIT 1").bind(email).first();

  if (existing) {
    const mergedTags = tagsToCsv([...tagList(existing.tags), ...tagList(input.tags)]);
    await db(env).prepare(
      `UPDATE contacts SET name=?, phone=?, email=?, tags=?, consent_sms=?, consent_email=?,
                          notes=CASE WHEN ?<>'' THEN ? ELSE notes END WHERE id=?`
    ).bind(
      clean(input.name, 120) || existing.name,
      phone || existing.phone,
      email || existing.email,
      mergedTags,
      input.consent_sms ? 1 : existing.consent_sms,     // ratchet up only
      input.consent_email ? 1 : existing.consent_email, // ratchet up only
      clean(input.notes, 1000), clean(input.notes, 1000),
      existing.id
    ).run();
    return "updated";
  }

  const id = uuid();
  await db(env).prepare(
    `INSERT INTO contacts (id,name,phone,email,tags,stage,notes,next_followup,consent_sms,consent_email,source,created)
     VALUES (?,?,?,?,?, 'lead', ?, '', ?, ?, ?, ?)`
  ).bind(
    id, clean(input.name, 120) || "Contact", phone, email, tagsToCsv(input.tags),
    clean(input.notes, 1000), input.consent_sms ? 1 : 0, input.consent_email ? 1 : 0,
    clean(input.source, 40) || "manual", nowIso()
  ).run();
  return "created";
}

// ============================================================================
// top-level PUBLIC router — called from worker.js BEFORE the admin block
// ============================================================================
// Returns a Response for a public marketing route (/u/:token, /api/hooks/twilio),
// or null to fall through. These are pre-auth by design.
async function handleMarketing(req, env, url) {
  const path = url.pathname;

  // Public: signed unsubscribe page.
  if (path.startsWith("/u/") && req.method === "GET") {
    return handleUnsubscribe(env, path.slice(3));
  }
  // Public: Twilio inbound webhook (signature-validated inside).
  if (path === "/api/hooks/twilio" && req.method === "POST") {
    return handleTwilioWebhook(req, env, url);
  }
  return null;
}

// ---------- minimal RFC-4180-ish CSV parser (quotes, commas, CRLF) ----------
function parseCsv(text) {
  const rows = [];
  let row = [], field = "", i = 0, inQ = false;
  const s = String(text).replace(/\r\n?/g, "\n");
  while (i < s.length) {
    const ch = s[i];
    if (inQ) {
      if (ch === '"') { if (s[i + 1] === '"') { field += '"'; i += 2; continue; } inQ = false; i++; continue; }
      field += ch; i++; continue;
    }
    if (ch === '"') { inQ = true; i++; continue; }
    if (ch === ",") { row.push(field); field = ""; i++; continue; }
    if (ch === "\n") { row.push(field); rows.push(row); row = []; field = ""; i++; continue; }
    field += ch; i++;
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}

