// marketing.js — SMS (Twilio) + Email (Resend) marketing backend for the
// adriancortez worker. Imported by src/worker.js:
//   import { handleMarketing, runCron } from "./marketing.js";
//
// ─── SHARED SCHEMA (read this first) ─────────────────────────────────────────
// This layer SHARES the `contacts` table that already exists from the CRM
// (migrations/0002_crm.sql). It does NOT recreate contacts. The marketing
// migration (0003_marketing.sql) only adds campaigns/sends/suppressions.
// The live contacts schema stores `created` as an ISO-8601 STRING and `phone`
// as TEXT DEFAULT '' (CRM's normPhone returns '' — never NULL — for unusable
// input). So: marketing INSERTs write `created` as new Date().toISOString()
// (NOT Date.now() — an integer there would break the CRM's created-DESC sort),
// and eligibility filters on `phone != ''` (NOT `IS NOT NULL`). The contacts
// table has extra CRM columns (stage, notes, next_followup) we leave at their
// defaults on marketing-side inserts.
//
// ─── A2P 10DLC PREREQUISITE (account-level, cannot be automated) ─────────────
// Before ANY marketing SMS is sent, Adrian's Twilio account MUST be registered
// under A2P 10DLC (Brand + Campaign) in the Twilio Console:
//   Messaging > Regulatory Compliance > A2P 10DLC.  Use-case: MARKETING/MIXED.
// Unregistered marketing traffic is carrier-filtered/blocked. This code enforces
// consent, suppression, opt-out keywords and quiet hours, but CANNOT substitute
// for carrier registration. If the number's carrier-level "Advanced Opt-Out"
// auto-reply is ON, disable it so subscribers don't get a duplicate STOP reply.

// ─── Constants ───────────────────────────────────────────────────────────────
const CHUNK_SIZE    = 50;      // sends drained per cron tick (well under the ~1000 subrequest limit)
const ENQUEUE_BATCH = 90;      // statements per D1 batch() (under D1's ~100-stmt cap)
const QUIET_START   = 9;       // 09:00 America/New_York — no SMS before this
const QUIET_END     = 20;      // 20:00 America/New_York — no SMS at/after this (exclusive)
const TZ            = "America/New_York";
const UNSUB_DAYS    = 30;      // signed email unsubscribe token validity
const OPT_OUT_FOOTER = " Txt STOP to opt out.";

const OPT_OUT_KEYWORDS = new Set(["STOP", "STOPALL", "UNSUBSCRIBE", "CANCEL", "QUIT", "END", "REVOKE", "OPTOUT"]);
const OPT_IN_KEYWORDS  = new Set(["START", "UNSTOP", "YES", "OPTIN"]);
const HELP_KEYWORDS    = new Set(["HELP", "INFO"]);

const STOP_REPLY  = "You're unsubscribed from Adrian Cortez Real Estate and will get no further texts. Reply START to re-subscribe.";
const START_REPLY = "You're re-subscribed to Adrian Cortez Real Estate. Reply STOP any time to opt out.";
const HELP_REPLY  = "Adrian Cortez Real Estate. Msg&data rates may apply. Reply STOP to opt out. Call (954) 665-0665 for help.";

// ─── Small helpers ───────────────────────────────────────────────────────────
const json = (data, status = 200, headers = {}) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json", "Cache-Control": "no-store", ...headers },
  });

const clean = (v, max = 500) => String(v ?? "").trim().slice(0, max);

/** Minimal XML escape for TwiML <Message> bodies. */
function escXml(s) {
  return String(s)
    .replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;").replace(/'/g, "&apos;");
}

/** Minimal HTML escape for the public unsubscribe page / email bodies. */
function escHtml(s) {
  return String(s ?? "")
    .replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;").replace(/'/g, "&#39;");
}

/** Constant-time compare of two equal-length strings (timing-safe). */
function safeEqual(a, b) {
  if (typeof a !== "string" || typeof b !== "string" || a.length !== b.length) return false;
  let diff = 0;
  for (let i = 0; i < a.length; i++) diff |= a.charCodeAt(i) ^ b.charCodeAt(i);
  return diff === 0;
}

/** HMAC-SHA256 hex (used for signed unsubscribe tokens; mirrors worker.js hmac()). */
async function hmacHex(secret, msg) {
  const key = await crypto.subtle.importKey(
    "raw", new TextEncoder().encode(secret), { name: "HMAC", hash: "SHA-256" }, false, ["sign"]
  );
  const sig = await crypto.subtle.sign("HMAC", key, new TextEncoder().encode(msg));
  return [...new Uint8Array(sig)].map((b) => b.toString(16).padStart(2, "0")).join("");
}

/**
 * Normalize a phone to E.164 (+1 default for 10-digit US). Returns "" (empty
 * string, NOT null) for unusable input, matching the CRM's normPhone contract
 * so the value written to contacts.phone stays consistent between the two layers.
 */
function normalizePhone(raw) {
  const s = String(raw ?? "").trim();
  const hadPlus = s.startsWith("+");
  const digits = s.replace(/\D/g, "");
  if (!digits) return "";
  if (hadPlus) return "+" + digits.slice(0, 15);
  if (digits.length === 10) return "+1" + digits;
  if (digits.length === 11 && digits[0] === "1") return "+" + digits;
  if (digits.length >= 8 && digits.length <= 15) return "+" + digits; // best-effort intl
  return "";
}

/** Merge {{name}} in a template with the contact's first name. */
function mergeBody(template, name) {
  const first = name ? String(name).trim().split(/\s+/)[0] : "there";
  return String(template).replace(/\{\{\s*name\s*\}\}/gi, first);
}

/** Append the STOP footer only if a STOP word isn't already present (word-boundary). */
function ensureFooter(body) {
  return /\bstop\b/i.test(body) ? body : body + OPT_OUT_FOOTER;
}

/** True when the current NY wall-clock hour is OUTSIDE the 09:00–20:00 send window. */
function isQuietHours() {
  const hour = Number(
    new Intl.DateTimeFormat("en-US", { timeZone: TZ, hour: "numeric", hour12: false }).format(new Date())
  );
  return hour < QUIET_START || hour >= QUIET_END;
}

// ─── D1 thin wrappers ────────────────────────────────────────────────────────
const dbAll   = async (db, sql, ...p) => (await db.prepare(sql).bind(...p).all()).results ?? [];
const dbFirst = async (db, sql, ...p) => (await db.prepare(sql).bind(...p).first()) ?? null;
const dbRun   = (db, sql, ...p) => db.prepare(sql).bind(...p).run();

// ─── Twilio ──────────────────────────────────────────────────────────────────

/**
 * Validate X-Twilio-Signature.
 * Twilio spec: base64( HMAC-SHA1( AUTH_TOKEN, fullURL + concat(sorted(key)(key+value)) ) )
 * https://www.twilio.com/docs/usage/webhooks/webhooks-security
 * Params sorted by key, each pair concatenated key+value with NO separator, appended
 * to the exact request URL. HMAC-SHA1 + base64 — SHA-256 (or hashing the raw body)
 * would 403 every genuine webhook and silently drop all STOP/HELP/START opt-outs.
 * Verified byte-identical to twilio-node's validateRequest().
 */
async function twilioSigValid(req, env, rawBody) {
  const signature = req.headers.get("X-Twilio-Signature") || "";
  if (!signature || !env.TWILIO_AUTH_TOKEN) return false;

  let data = req.url; // Workers see the exact public URL Twilio was configured with
  const ct = req.headers.get("Content-Type") || "";
  if (ct.includes("application/x-www-form-urlencoded")) {
    const params = [...new URLSearchParams(rawBody).entries()].sort(([a], [b]) => (a < b ? -1 : a > b ? 1 : 0));
    for (const [k, v] of params) data += k + v;
  }

  const key = await crypto.subtle.importKey(
    "raw", new TextEncoder().encode(env.TWILIO_AUTH_TOKEN), { name: "HMAC", hash: "SHA-1" }, false, ["sign"]
  );
  const sig = await crypto.subtle.sign("HMAC", key, new TextEncoder().encode(data));
  const b64 = btoa(String.fromCharCode(...new Uint8Array(sig)));
  return safeEqual(b64, signature);
}

/** Send one SMS via the Twilio REST API (fetch, no SDK). Returns { sid, error }. */
async function twilioSend(env, to, body) {
  if (!env.TWILIO_ACCOUNT_SID || !env.TWILIO_AUTH_TOKEN || !env.TWILIO_FROM) {
    return { sid: null, error: "Twilio secrets not configured" };
  }
  const creds  = btoa(`${env.TWILIO_ACCOUNT_SID}:${env.TWILIO_AUTH_TOKEN}`);
  const params = new URLSearchParams({ To: to, From: env.TWILIO_FROM, Body: body });
  try {
    const res = await fetch(
      `https://api.twilio.com/2010-04-01/Accounts/${env.TWILIO_ACCOUNT_SID}/Messages.json`,
      { method: "POST", headers: { Authorization: `Basic ${creds}`, "Content-Type": "application/x-www-form-urlencoded" }, body: params }
    );
    const text = await res.text();
    let data = {};
    try { data = JSON.parse(text); } catch { /* non-JSON error body */ }
    if (!res.ok) return { sid: null, error: data.message || `Twilio HTTP ${res.status}` };
    return { sid: data.sid, error: null };
  } catch (err) {
    return { sid: null, error: String(err) };
  }
}

// ─── Resend (email) ──────────────────────────────────────────────────────────

/** Signed, expiring unsubscribe token: b64url(email).exp.hmac */
async function makeUnsubToken(env, email) {
  const secret = env.RESEND_UNSUB_SECRET || env.ADMIN_KEY;
  const exp = Date.now() + UNSUB_DAYS * 86400 * 1000;
  const lower = String(email).toLowerCase();
  const sig = await hmacHex(secret, `unsub:${lower}:${exp}`);
  const b64 = btoa(lower).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
  return `${b64}.${exp}.${sig}`;
}

/** Verify + decode an unsubscribe token. Returns the email or null. */
async function verifyUnsubToken(env, token) {
  try {
    const secret = env.RESEND_UNSUB_SECRET || env.ADMIN_KEY;
    const [b64, exp, sig] = String(token).split(".");
    if (!b64 || !exp || !sig) return null;
    if (Number(exp) < Date.now()) return null;
    const padded = b64.replace(/-/g, "+").replace(/_/g, "/");
    const email = atob(padded + "=".repeat((4 - (padded.length % 4)) % 4)).toLowerCase();
    const expect = await hmacHex(secret, `unsub:${email}:${exp}`);
    return safeEqual(sig, expect) ? email : null;
  } catch {
    return null;
  }
}

/** Send one marketing email via Resend. Returns { id, error }. */
async function resendSend(env, to, subject, htmlBody, textBody, unsubUrl) {
  if (!env.RESEND_API_KEY || !env.EMAIL_FROM) {
    return { id: null, error: "Resend secrets not configured" };
  }
  try {
    const res = await fetch("https://api.resend.com/emails", {
      method: "POST",
      headers: { Authorization: `Bearer ${env.RESEND_API_KEY}`, "Content-Type": "application/json" },
      body: JSON.stringify({
        from: env.EMAIL_FROM,
        to: [to],
        subject,
        html: htmlBody,
        text: textBody,
        headers: {
          "List-Unsubscribe": `<${unsubUrl}>`,
          "List-Unsubscribe-Post": "List-Unsubscribe=One-Click",
        },
      }),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok) return { id: null, error: data.message || `Resend HTTP ${res.status}` };
    return { id: data.id, error: null };
  } catch (err) {
    return { id: null, error: String(err) };
  }
}

