</style></head><body><div class="card">${bodyHtml}</div></body></html>`,
    { status, headers: { "Content-Type": "text/html;charset=UTF-8", "Cache-Control": "no-store" } }
  );
}

// ─── Suppression + consent helpers ───────────────────────────────────────────

async function isSuppressed(db, value, channel) {
  if (!value) return true;
  const row = await dbFirst(
    db, "SELECT 1 AS x FROM suppressions WHERE value=? AND channel=? LIMIT 1", value, channel
  );
  return !!row;
}

async function addSuppression(db, value, channel, reason) {
  if (!value) return;
  await dbRun(
    db, "INSERT OR REPLACE INTO suppressions (value,channel,reason,ts) VALUES (?,?,?,?)",
    value, channel, reason, Date.now()
  );
}

async function removeSuppression(db, value, channel) {
  await dbRun(db, "DELETE FROM suppressions WHERE value=? AND channel=?", value, channel);
}

/** Preload all suppressed values for a channel into a Set (one query, no per-contact loop). */
async function loadSuppressionSet(db, channel) {
  const rows = await dbAll(db, "SELECT value FROM suppressions WHERE channel=?", channel);
  return new Set(rows.map((r) => String(r.value)));
}

// ─── Tag segmentation ────────────────────────────────────────────────────────
// contacts.tags is a comma-separated string. A contact matches when it carries
// ALL listed tags. Wrapping with commas lets ',tag,' LIKE match any position.
function buildSegmentSql(segment) {
  const tags = String(segment || "").split(",").map((t) => t.trim()).filter(Boolean);
  if (!tags.length) return { where: "", params: [] };
  const where = tags.map(() => "(',' || IFNULL(tags,'') || ',') LIKE ?").join(" AND ");
  const params = tags.map((t) => `%,${t},%`);
  return { where: " WHERE " + where, params };
}

// ─── Enqueue (batched, subrequest-safe) ──────────────────────────────────────
/**
 * Build send rows for a campaign in ONE pass: select matching contacts, pre-load
 * the channel's suppression set (one query), then INSERT every row via chunked
 * env.DB.batch(). Ineligible contacts (no consent / no destination / suppressed)
 * are inserted as status='suppressed' so campaign stats are complete. Runs at
 * activation (/send or cron), never as a per-contact HTTP loop.
 */
async function enqueueCampaign(db, campaign) {
  const channel = campaign.channel;
  const { where, params } = buildSegmentSql(campaign.segment);
  const contacts = await dbAll(db, `SELECT id,name,phone,email,consent_sms,consent_email FROM contacts${where}`, ...params);
  const supp = await loadSuppressionSet(db, channel);

  const ts = Date.now();
  const stmts = [db.prepare("UPDATE campaigns SET status='sending', scheduled_at=NULL WHERE id=?").bind(campaign.id)];

  for (const c of contacts) {
    let value, eligible;
    if (channel === "sms") {
      value = normalizePhone(c.phone);
      eligible = !!c.consent_sms && !!value && !supp.has(value);
    } else {
      value = (c.email || "").toLowerCase().trim() || null;
      eligible = !!c.consent_email && !!value && !supp.has(value);
    }
    stmts.push(
      db.prepare(
        "INSERT OR IGNORE INTO sends (campaign_id,contact_id,channel,status,ts) VALUES (?,?,?,?,?)"
      ).bind(campaign.id, c.id, channel, eligible ? "queued" : "suppressed", ts)
    );
  }

  for (let i = 0; i < stmts.length; i += ENQUEUE_BATCH) {
    await db.batch(stmts.slice(i, i + ENQUEUE_BATCH));
  }
  return { total: contacts.length, queued: stmts.length - 1 }; // minus the UPDATE
}

/** Count eligible recipients for the composer preview (batched, no per-contact query). */
async function countRecipients(db, channel, segment) {
  const { where, params } = buildSegmentSql(segment);
  const contacts = await dbAll(db, `SELECT phone,email,consent_sms,consent_email FROM contacts${where}`, ...params);
  const supp = await loadSuppressionSet(db, channel);
  let n = 0;
  for (const c of contacts) {
    if (channel === "sms") {
      const p = normalizePhone(c.phone);
      if (c.consent_sms && p && !supp.has(p)) n++;
    } else {
      const e = (c.email || "").toLowerCase().trim();
      if (c.consent_email && e && !supp.has(e)) n++;
    }
  }
  return n;
}

// ─── Cron: drain the send queue ──────────────────────────────────────────────
export async function runCron(env) {
  if (!env.DB) return; // DB not bound
  const db = env.DB;
  const now = Date.now();
  const quiet = isQuietHours();

  // 1. Activate scheduled campaigns whose time has come.
  //    SMS campaigns wait during quiet hours; email may proceed.
  const due = await dbAll(db, "SELECT * FROM campaigns WHERE status='scheduled' AND scheduled_at IS NOT NULL AND scheduled_at<=?", now);
  for (const camp of due) {
    if (camp.channel === "sms" && quiet) continue; // hold until the window opens
    await enqueueCampaign(db, camp);
  }

  // 2. Drain up to CHUNK_SIZE queued rows. During quiet hours, email only.
  const channelFilter = quiet ? " AND s.channel='email'" : "";
  const rows = await dbAll(
    db,
    `SELECT s.id, s.channel, s.campaign_id, s.contact_id,
            c.body AS camp_body, c.subject AS camp_subject,
            ct.name AS ct_name, ct.phone AS ct_phone, ct.email AS ct_email,
            ct.consent_sms, ct.consent_email
       FROM sends s
       JOIN campaigns c ON c.id = s.campaign_id
       JOIN contacts  ct ON ct.id = s.contact_id
      WHERE s.status='queued' AND c.status='sending'${channelFilter}
      ORDER BY s.id ASC
      LIMIT ?`,
    CHUNK_SIZE
  );

  for (const row of rows) {
    if (row.channel === "sms") {
      if (isQuietHours()) continue; // re-check per row; never send SMS off-window
      const phone = normalizePhone(row.ct_phone);
      // Fail-closed: re-check consent + suppression at SEND time (a STOP may have
      // arrived after the queue was built).
      if (!row.consent_sms || !phone) {
        await dbRun(db, "UPDATE sends SET status='suppressed', error='no consent or phone', ts=? WHERE id=?", Date.now(), row.id);
        continue;
      }
      if (await isSuppressed(db, phone, "sms")) {
        await dbRun(db, "UPDATE sends SET status='suppressed', error='suppressed', ts=? WHERE id=?", Date.now(), row.id);
        continue;
      }
      const body = ensureFooter(mergeBody(row.camp_body, row.ct_name));
      const { sid, error } = await twilioSend(env, phone, body);
      if (error) await dbRun(db, "UPDATE sends SET status='failed', error=?, ts=? WHERE id=?", error, Date.now(), row.id);
      else       await dbRun(db, "UPDATE sends SET status='sent', provider_id=?, ts=? WHERE id=?", sid || "", Date.now(), row.id);
    } else {
      const email = (row.ct_email || "").toLowerCase().trim();
      if (!row.consent_email || !email) {
        await dbRun(db, "UPDATE sends SET status='suppressed', error='no consent or email', ts=? WHERE id=?", Date.now(), row.id);
        continue;
      }
      if (await isSuppressed(db, email, "email")) {
        await dbRun(db, "UPDATE sends SET status='suppressed', error='suppressed', ts=? WHERE id=?", Date.now(), row.id);
        continue;
      }
      const merged   = mergeBody(row.camp_body, row.ct_name);
      const subject  = row.camp_subject || "A note from Adrian Cortez";
      const origin   = env.SITE_ORIGIN || "https://adriancortez.com";
      const token    = await makeUnsubToken(env, email);
      const unsubUrl = `${origin}/u/${encodeURIComponent(token)}`;
      const { id, error } = await resendSend(env, email, subject, emailHtml(subject, merged, unsubUrl), merged, unsubUrl);
      if (error) await dbRun(db, "UPDATE sends SET status='failed', error=?, ts=? WHERE id=?", error, Date.now(), row.id);
      else       await dbRun(db, "UPDATE sends SET status='sent', provider_id=?, ts=? WHERE id=?", id || "", Date.now(), row.id);
    }
  }

  // 3. Mark campaigns complete once they have no queued rows left.
  const activeIds = new Set(
    (await dbAll(db, "SELECT DISTINCT campaign_id FROM sends WHERE status='queued'")).map((r) => r.campaign_id)
  );
  const sending = await dbAll(db, "SELECT id FROM campaigns WHERE status='sending'");
  for (const camp of sending) {
    if (!activeIds.has(camp.id)) {
      await dbRun(db, "UPDATE campaigns SET status='sent' WHERE id=?", camp.id);
    }
  }
}

// ─── Inbound Twilio webhook: STOP / HELP / START ─────────────────────────────
async function handleTwilioInbound(req, env) {
  const rawBody = await req.text();

  // Reject anything not signed by Twilio (empty TwiML so Twilio doesn't retry-storm).
  if (!(await twilioSigValid(req, env, rawBody))) {
    return new Response(`<?xml version="1.0" encoding="UTF-8"?><Response></Response>`, {
      status: 403, headers: { "Content-Type": "text/xml" },
    });
  }

  const params = new URLSearchParams(rawBody);
  const fromRaw = (params.get("From") || "").trim();
  const from = normalizePhone(fromRaw) || fromRaw; // normalize so key matches send-time lookup
  // First word, uppercased, punctuation stripped — matches "STOP", "STOP.", "Stop!".
  const word = (params.get("Body") || "").trim().toUpperCase().split(/\s+/)[0].replace(/[^A-Z]/g, "");

  let reply = "";
  if (env.DB) {
    if (OPT_OUT_KEYWORDS.has(word)) {
      await addSuppression(env.DB, from, "sms", "STOP keyword");
      await dbRun(env.DB, "UPDATE contacts SET consent_sms=0 WHERE phone=?", from);
      reply = STOP_REPLY;
    } else if (OPT_IN_KEYWORDS.has(word)) {
      await removeSuppression(env.DB, from, "sms");
      await dbRun(env.DB, "UPDATE contacts SET consent_sms=1 WHERE phone=?", from);
      reply = START_REPLY;
    } else if (HELP_KEYWORDS.has(word)) {
      reply = HELP_REPLY;
    }
  }

  const twiml = reply
    ? `<?xml version="1.0" encoding="UTF-8"?><Response><Message>${escXml(reply)}</Message></Response>`
    : `<?xml version="1.0" encoding="UTF-8"?><Response></Response>`;
  return new Response(twiml, { status: 200, headers: { "Content-Type": "text/xml" } });
}

// ─── CSV parser (server-side; handles quoted fields + escaped quotes) ─────────
function parseCsv(text) {
  const lines = String(text).replace(/\r\n?/g, "\n").split("\n").filter((l) => l.trim() !== "");
  if (!lines.length) return [];
  const first = lines[0].toLowerCase();
  const hasHeader = /name|phone|email|tag/.test(first);
  const headers = hasHeader
    ? splitCsvLine(lines[0]).map((h) => h.trim().toLowerCase().replace(/\s+/g, "_"))
    : ["name", "phone", "email", "tags", "consent_sms", "consent_email"];
  const rows = [];
  for (let i = hasHeader ? 1 : 0; i < lines.length; i++) {
    const vals = splitCsvLine(lines[i]);
    const row = {};
    headers.forEach((h, idx) => { row[h] = (vals[idx] || "").trim(); });
    rows.push(row);
  }
  return rows;
}
function splitCsvLine(line) {
  const out = [];
  let cur = "", q = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"') {
      if (q && line[i + 1] === '"') { cur += '"'; i++; } else q = !q;
    } else if (c === "," && !q) { out.push(cur); cur = ""; }
    else cur += c;
  }
  out.push(cur);
  return out;
}
const truthy = (v) => v === 1 || v === true || v === "1" || String(v).toLowerCase() === "true" || String(v).toLowerCase() === "yes";

// ─── Contacts routes ─────────────────────────────────────────────────────────
// NOTE: marketing writes into the SHARED contacts table. It sets the CRM-owned
// columns (stage/notes/next_followup) to their table defaults via omission and
// writes `created` as an ISO string to match the CRM's sort order.
async function handleContacts(req, env, url) {
  const db = env.DB, path = url.pathname, method = req.method;

  if (path === "/api/admin/contacts") {
    if (method === "GET") {
      const q = url.searchParams.get("q") || "";
      const tag = url.searchParams.get("tag") || "";
      let rows;
      if (q) {
        const like = `%${q}%`;
        rows = await dbAll(db,
          "SELECT * FROM contacts WHERE name LIKE ? OR phone LIKE ? OR email LIKE ? OR tags LIKE ? ORDER BY created DESC LIMIT 500",
          like, like, like, like);
      } else if (tag) {
        rows = await dbAll(db,
          "SELECT * FROM contacts WHERE (',' || IFNULL(tags,'') || ',') LIKE ? ORDER BY created DESC LIMIT 500",
          `%,${tag},%`);
      } else {
        rows = await dbAll(db, "SELECT * FROM contacts ORDER BY created DESC LIMIT 500");
      }
      return json({ contacts: rows });
    }
    if (method === "POST") {
      let b; try { b = await req.json(); } catch { return json({ error: "bad json" }, 400); }
      const phone = normalizePhone(b.phone);
      const email = clean(b.email, 160).toLowerCase() || null;
      if (!clean(b.name)) return json({ error: "name required" }, 422);
      if (!phone && !email) return json({ error: "phone or email required" }, 422);
      const id = crypto.randomUUID();
      // Only marketing-relevant columns; CRM columns keep their schema defaults.
      await dbRun(db,
        `INSERT INTO contacts (id,name,phone,email,tags,consent_sms,consent_email,source,notes,created)
         VALUES (?,?,?,?,?,?,?,?,?,?)`,
        id, clean(b.name, 120), phone, email, clean(b.tags, 300),
        b.consent_sms ? 1 : 0, b.consent_email ? 1 : 0,
        clean(b.source, 60) || "manual", clean(b.notes, 2000), new Date().toISOString());
      return json({ ok: true, id });
    }
  }

  // Import from CSV rows (array of objects) or raw csv text — batched insert
  if (path === "/api/admin/contacts/import" && method === "POST") {
    let payload; try { payload = await req.json(); } catch { return json({ error: "bad json" }, 400); }
    const rows = Array.isArray(payload) ? payload : parseCsv(clean(payload.csv, 1_000_000));
    let imported = 0, skipped = 0;
    const stmts = [];
    const nowIso = new Date().toISOString();
    for (const r of rows.slice(0, 5000)) {
      const name = clean(r.name || r.Name, 120);
      const phone = normalizePhone(r.phone || r.Phone || r.mobile || r.Mobile);
      const email = clean(r.email || r.Email, 160).toLowerCase() || null;
      if (!name || (!phone && !email)) { skipped++; continue; }
      stmts.push(db.prepare(
        `INSERT INTO contacts (id,name,phone,email,tags,consent_sms,consent_email,source,notes,created)
         VALUES (?,?,?,?,?,?,?,?,?,?)`
      ).bind(
        crypto.randomUUID(), name, phone, email, clean(r.tags || r.Tags, 300),
        truthy(r.consent_sms) ? 1 : 0, truthy(r.consent_email) ? 1 : 0,
        "csv_import", clean(r.notes || r.Notes, 2000), nowIso
      ));
      imported++;
    }
    for (let i = 0; i < stmts.length; i += ENQUEUE_BATCH) await db.batch(stmts.slice(i, i + ENQUEUE_BATCH));
    return json({ ok: true, imported, skipped });
  }

  // Import from the KV lead inbox (consent OFF — a lead form is not SMS consent).
  // Deduped on phone OR email so it plays nicely with CRM's own import-leads.
  if (path === "/api/admin/contacts/import-leads" && method === "POST") {
    const list = await env.SITE.list({ prefix: "lead:", limit: 500 });
    let imported = 0, skipped = 0;
    for (const k of list.keys) {
      const v = await env.SITE.get(k.name);
      if (!v) continue;
      let lead; try { lead = JSON.parse(v); } catch { continue; }
      const name = clean(lead.name, 120);
      const phone = normalizePhone(lead.phone);
      const email = clean(lead.email, 160).toLowerCase() || null;
      if (!name || (!phone && !email)) { skipped++; continue; }
      let exists = phone ? await dbFirst(db, "SELECT id FROM contacts WHERE phone=?", phone) : null;
      if (!exists && email) exists = await dbFirst(db, "SELECT id FROM contacts WHERE email=?", email);
      if (exists) { skipped++; continue; }
      await dbRun(db,
        `INSERT INTO contacts (id,name,phone,email,tags,stage,consent_sms,consent_email,source,notes,created)
         VALUES (?,?,?,?,?,?,?,?,?,?,?)`,
        crypto.randomUUID(), name, phone, email, "lead", "lead",
        0, 0, "lead_inbox", clean(lead.message, 2000),
        new Date(lead.ts || Date.now()).toISOString());
      imported++;
    }
    return json({ ok: true, imported, skipped });
  }

  const one = path.match(/^\/api\/admin\/contacts\/([^/]+)$/);
  if (one) {
    const id = decodeURIComponent(one[1]);
    if (method === "GET") {
      const row = await dbFirst(db, "SELECT * FROM contacts WHERE id=?", id);
      return row ? json(row) : json({ error: "not found" }, 404);
    }
    if (method === "PUT") {
      let b; try { b = await req.json(); } catch { return json({ error: "bad json" }, 400); }
      const phone = normalizePhone(b.phone);
      const email = clean(b.email, 160).toLowerCase() || null;
      // Only touch marketing-owned fields; leave stage/notes/next_followup to the CRM.
      await dbRun(db,
        "UPDATE contacts SET name=?,phone=?,email=?,tags=?,consent_sms=?,consent_email=?,source=? WHERE id=?",
        clean(b.name, 120), phone, email, clean(b.tags, 300),
        b.consent_sms ? 1 : 0, b.consent_email ? 1 : 0,
        clean(b.source, 60) || "manual", id);
      return json({ ok: true });
    }
    if (method === "DELETE") {
      await dbRun(db, "DELETE FROM activities WHERE contact_id=?", id);
      await dbRun(db, "DELETE FROM contacts WHERE id=?", id);
      return json({ ok: true });
    }
  }
  return null;
}

// ─── Campaigns routes ────────────────────────────────────────────────────────
async function handleCampaigns(req, env, url) {
  const db = env.DB, path = url.pathname, method = req.method;

  if (path === "/api/admin/campaigns") {
    if (method === "GET") {
      const rows = await dbAll(db,
        `SELECT c.*,
          (SELECT COUNT(*) FROM sends s WHERE s.campaign_id=c.id AND s.status='queued')     AS cnt_queued,
          (SELECT COUNT(*) FROM sends s WHERE s.campaign_id=c.id AND s.status='sent')       AS cnt_sent,
          (SELECT COUNT(*) FROM sends s WHERE s.campaign_id=c.id AND s.status='failed')     AS cnt_failed,
          (SELECT COUNT(*) FROM sends s WHERE s.campaign_id=c.id AND s.status='suppressed') AS cnt_suppressed
         FROM campaigns c ORDER BY c.created DESC LIMIT 100`);
      return json({ campaigns: rows });
    }
    if (method === "POST") {
      let b; try { b = await req.json(); } catch { return json({ error: "bad json" }, 400); }
      if (!["sms", "email"].includes(b.channel)) return json({ error: "channel must be sms or email" }, 422);
      if (!clean(b.name)) return json({ error: "name required" }, 422);
      if (!clean(b.body, 5000)) return json({ error: "body required" }, 422);
      const id = crypto.randomUUID();
      await dbRun(db,
        `INSERT INTO campaigns (id,channel,name,subject,body,segment,status,scheduled_at,created)
         VALUES (?,?,?,?,?,?,?,?,?)`,
        id, b.channel, clean(b.name, 200), clean(b.subject, 300), clean(b.body, 5000),
        clean(b.segment, 300), "draft", null, new Date().toISOString());
      return json({ ok: true, id });
    }
  }

  // Recipient count preview
  if (path === "/api/admin/campaigns/recipient-count" && method === "GET") {
    const channel = url.searchParams.get("channel") || "";
    const segment = url.searchParams.get("segment") || "";
    if (!["sms", "email"].includes(channel)) return json({ error: "invalid channel" }, 422);
    return json({ count: await countRecipients(db, channel, segment) });
  }

  const one = path.match(/^\/api\/admin\/campaigns\/([^/]+)$/);
  if (one) {
    const id = decodeURIComponent(one[1]);
    if (method === "GET") {
      const row = await dbFirst(db, "SELECT * FROM campaigns WHERE id=?", id);
      if (!row) return json({ error: "not found" }, 404);
      const stats = await dbAll(db, "SELECT status, COUNT(*) AS n FROM sends WHERE campaign_id=? GROUP BY status", id);
      const s = {}; for (const r of stats) s[r.status] = r.n;
      return json({ ...row, stats: s });
    }
    if (method === "PUT") {
      let b; try { b = await req.json(); } catch { return json({ error: "bad json" }, 400); }
      const cur = await dbFirst(db, "SELECT status FROM campaigns WHERE id=?", id);
      if (!cur) return json({ error: "not found" }, 404);
      if (!["draft", "paused"].includes(cur.status)) return json({ error: "only draft/paused campaigns can be edited" }, 409);
      await dbRun(db,
        "UPDATE campaigns SET name=?,subject=?,body=?,segment=? WHERE id=?",
        clean(b.name, 200), clean(b.subject, 300), clean(b.body, 5000), clean(b.segment, 300), id);
      return json({ ok: true });
    }
    if (method === "DELETE") {
      const cur = await dbFirst(db, "SELECT status FROM campaigns WHERE id=?", id);
      if (!cur) return json({ error: "not found" }, 404);
      if (cur.status === "sending" || cur.status === "scheduled")
        return json({ error: "pause the campaign before deleting" }, 409);
      await dbRun(db, "DELETE FROM sends WHERE campaign_id=?", id);
      await dbRun(db, "DELETE FROM campaigns WHERE id=?", id);
      return json({ ok: true });
    }
  }

  // Test send to Adrian only (no queue, no suppression list — a preview)
  const testM = path.match(/^\/api\/admin\/campaigns\/([^/]+)\/test$/);
  if (testM && method === "POST") {
    const camp = await dbFirst(db, "SELECT * FROM campaigns WHERE id=?", decodeURIComponent(testM[1]));
    if (!camp) return json({ error: "not found" }, 404);
    let b; try { b = await req.json(); } catch { return json({ error: "bad json" }, 400); }
    if (camp.channel === "sms") {
      const to = normalizePhone(b.to);
      if (!to) return json({ error: "valid test phone required" }, 422);
      const body = ensureFooter("[TEST] " + mergeBody(camp.body, b.name || "Adrian"));
      const { sid, error } = await twilioSend(env, to, body);
      return error ? json({ ok: false, error }) : json({ ok: true, sid });
    }
    const to = clean(b.to, 160).toLowerCase();
    if (!to) return json({ error: "valid test email required" }, 422);
    const merged = mergeBody(camp.body, b.name || "Adrian");
    const subject = "[TEST] " + (camp.subject || "A note from Adrian Cortez");
    const origin = env.SITE_ORIGIN || "https://adriancortez.com";
    const token = await makeUnsubToken(env, to);
    const unsubUrl = `${origin}/u/${encodeURIComponent(token)}`;
    const { id, error } = await resendSend(env, to, subject, emailHtml(subject, merged, unsubUrl), merged, unsubUrl);
    return error ? json({ ok: false, error }) : json({ ok: true, id });
  }

  // Send now — requires typed confirmation
  const sendM = path.match(/^\/api\/admin\/campaigns\/([^/]+)\/send$/);
  if (sendM && method === "POST") {
    let b; try { b = await req.json(); } catch { return json({ error: "bad json" }, 400); }
    if (b.confirm !== "SEND") return json({ error: 'typed confirmation required: {confirm:"SEND"}' }, 422);
    const camp = await dbFirst(db, "SELECT * FROM campaigns WHERE id=?", decodeURIComponent(sendM[1]));
    if (!camp) return json({ error: "not found" }, 404);
    if (!["draft", "paused"].includes(camp.status)) return json({ error: "campaign already scheduled/sending/sent" }, 409);
    if (camp.channel === "sms" && isQuietHours())
      return json({ error: "SMS can only send 9am–8pm ET. Schedule it or wait for the window." }, 422);
    const { queued } = await enqueueCampaign(db, camp); // sets status='sending'
    return json({ ok: true, queued });
  }

  // Schedule for later
  const schedM = path.match(/^\/api\/admin\/campaigns\/([^/]+)\/schedule$/);
  if (schedM && method === "POST") {
    let b; try { b = await req.json(); } catch { return json({ error: "bad json" }, 400); }
    const when = Number(b.scheduled_at);
    if (!when || Number.isNaN(when)) return json({ error: "scheduled_at (unix ms) required" }, 422);
    const id = decodeURIComponent(schedM[1]);
    const camp = await dbFirst(db, "SELECT status FROM campaigns WHERE id=?", id);
    if (!camp) return json({ error: "not found" }, 404);
    if (!["draft", "paused"].includes(camp.status)) return json({ error: "only draft/paused campaigns can be scheduled" }, 409);
    await dbRun(db, "UPDATE campaigns SET status='scheduled', scheduled_at=? WHERE id=?", when, id);
    return json({ ok: true, scheduled_at: when });
  }

  // Pause (stops the cron from draining more; queued rows stay queued)
  const pauseM = path.match(/^\/api\/admin\/campaigns\/([^/]+)\/pause$/);
  if (pauseM && method === "POST") {
    await dbRun(db, "UPDATE campaigns SET status='paused' WHERE id=? AND status IN ('scheduled','sending')", decodeURIComponent(pauseM[1]));
    return json({ ok: true });
  }

  return null;
}

// ─── Router (called from worker.js) ──────────────────────────────────────────
export async function handleMarketing(req, env, url, isAdminFn) {
  const path = url.pathname, method = req.method;

  // Public: inbound Twilio webhook (self-authenticating via signature)
  if (path === "/api/hooks/twilio" && method === "POST") {
    return handleTwilioInbound(req, env);
  }

  // Public: one-click email unsubscribe. NOTE: /u/ is NOT under /api/*, so
  // run_worker_first won't force it to the worker — but this router is called at
  // the top of fetch() before the env.ASSETS.fetch() fallback, so /u/ still reaches us.
  const unsub = path.match(/^\/u\/([^/]+)$/);
  if (unsub && (method === "GET" || method === "POST")) {
    const email = await verifyUnsubToken(env, decodeURIComponent(unsub[1]));
    if (!email) {
      return publicPage(
        `<h1>AC<span>.</span></h1><p>This unsubscribe link is invalid or has expired.</p>
         <p>To be removed, reply <span class="em">STOP</span> to any text or email
         <a href="mailto:adrian@adriancortez.com" style="color:#14594E">adrian@adriancortez.com</a>.</p>`, 400);
    }
    if (env.DB) {
      await addSuppression(env.DB, email, "email", "unsubscribe_link");
      await dbRun(env.DB, "UPDATE contacts SET consent_email=0 WHERE LOWER(email)=LOWER(?)", email);
    }
    return publicPage(
      `<h1>AC<span>.</span></h1><p>You've been unsubscribed from Adrian Cortez emails.</p>
       <p class="em">${escHtml(email)}</p>
       <p>You won't receive any further marketing emails from us.</p>`);
  }

  // Everything below is admin-gated marketing API. Return null for admin paths we
  // don't own so the existing worker.js admin routes (crm, content, leads) still run.
  if (!path.startsWith("/api/admin/")) return null;
  const owned =
    path.startsWith("/api/admin/contacts") ||
    path.startsWith("/api/admin/campaigns") ||
    path === "/api/admin/suppressions" ||
    path === "/api/admin/marketing/status";
  if (!owned) return null;

  if (!(await isAdminFn(req, env))) return json({ error: "unauthorized" }, 401);
  if (!env.DB) return json({ error: "database not provisioned yet" }, 503);

  if (path === "/api/admin/marketing/status" && method === "GET") {
    return json({ quiet_hours: isQuietHours(), tz: TZ, quiet_start: QUIET_START, quiet_end: QUIET_END });
  }

  if (path === "/api/admin/suppressions" && method === "GET") {
    const rows = await dbAll(env.DB, "SELECT * FROM suppressions ORDER BY ts DESC LIMIT 500");
    return json({ suppressions: rows });
  }

  if (path.startsWith("/api/admin/contacts")) {
    const r = await handleContacts(req, env, url);
    if (r) return r;
  }
  if (path.startsWith("/api/admin/campaigns")) {
    const r = await handleCampaigns(req, env, url);
    if (r) return r;
  }

  return json({ error: "not found" }, 404);
}
