-- adriancortez marketing layer. Renumbered 0003 (0002_crm.sql already exists and
-- CREATED the shared `contacts` table). This migration does NOT touch contacts —
-- it only adds campaigns/sends/suppressions. Marketing code reads/writes the
-- existing contacts columns (name/phone/email/tags/consent_sms/consent_email/
-- source/notes/created) and writes `created` as an ISO string to match the CRM.
-- Apply: wrangler d1 execute adriancortez-marketing --file=migrations/0003_marketing.sql --remote
-- Local: drop --remote.
-- NOTE: campaigns/sends/suppressions timestamps are Unix ms (Date.now()); only
-- the shared contacts.created stays an ISO string (owned by the CRM).

CREATE TABLE IF NOT EXISTS campaigns (
  id           TEXT PRIMARY KEY,
  channel      TEXT NOT NULL CHECK (channel IN ('sms','email')),
  name         TEXT NOT NULL,
  subject      TEXT NOT NULL DEFAULT '',       -- email subject; unused for SMS
  body         TEXT NOT NULL,                  -- supports {{name}} merge
  segment      TEXT NOT NULL DEFAULT '',       -- comma-separated tag filter; blank = all
  status       TEXT NOT NULL DEFAULT 'draft'
                 CHECK (status IN ('draft','scheduled','sending','sent','paused')),
  scheduled_at INTEGER,                        -- Unix ms; NULL = not scheduled
  created      TEXT NOT NULL                   -- ISO-8601 string (matches CRM convention)
);
CREATE INDEX IF NOT EXISTS campaigns_status ON campaigns(status, scheduled_at);
CREATE INDEX IF NOT EXISTS campaigns_created ON campaigns(created DESC);

CREATE TABLE IF NOT EXISTS sends (
  id          INTEGER PRIMARY KEY AUTOINCREMENT,
  campaign_id TEXT NOT NULL,
  contact_id  TEXT NOT NULL,
  channel     TEXT NOT NULL,
  status      TEXT NOT NULL DEFAULT 'queued'
                CHECK (status IN ('queued','sent','delivered','failed','suppressed')),
  provider_id TEXT,                            -- Twilio SID or Resend id
  error       TEXT,
  ts          INTEGER NOT NULL,                -- Unix ms
  UNIQUE (campaign_id, contact_id)
);
CREATE INDEX IF NOT EXISTS sends_campaign ON sends(campaign_id, status);
CREATE INDEX IF NOT EXISTS sends_queue    ON sends(status, id);

CREATE TABLE IF NOT EXISTS suppressions (
  value   TEXT NOT NULL,                       -- phone (E.164) or lowercase email
  channel TEXT NOT NULL CHECK (channel IN ('sms','email')),
  reason  TEXT NOT NULL DEFAULT '',            -- STOP keyword | unsubscribe_link | bounce | manual
  ts      INTEGER NOT NULL,
  PRIMARY KEY (value, channel)
);
CREATE INDEX IF NOT EXISTS suppressions_value ON suppressions(value);
