(function () {
  "use strict";

  const MKT_TABS  = ["contacts", "campaigns"];
  const CORE_TABS = ["leads", "crm", "listings", "copy"];

  // Wait until the base admin script has defined its helpers + shell.
  function ready() {
    return typeof window.$ === "function" && typeof window.esc === "function" &&
           typeof window.api === "function" && document.querySelector(".tabs") &&
           document.querySelector("main");
  }
  (function boot() {
    if (!ready()) return void setTimeout(boot, 100);
    injectTabs();
    injectPanels();
    hookCoreTabs();
  })();

  const $   = window.$;
  const esc = window.esc;
  const api = window.api;
  const fmt = (n) => (n == null ? "0" : String(n));
  const debounce = (fn, ms) => { let t; return (...a) => { clearTimeout(t); t = setTimeout(() => fn(...a), ms); }; };

  // ── tab wiring ─────────────────────────────────────────────────────────────
  function injectTabs() {
    const bar = document.querySelector(".tabs");
    if (bar.querySelector('button[data-tab="contacts"]')) return;
    MKT_TABS.forEach((t) => {
      const b = document.createElement("button");
      b.dataset.tab = t;
      b.textContent = t === "contacts" ? "Contacts" : "Campaigns";
      b.addEventListener("click", () => showMktTab(t, b));
      bar.appendChild(b);
    });
  }

  // When a CORE tab is clicked, hide our panels + deactivate our buttons.
  function hookCoreTabs() {
    document.querySelectorAll(".tabs button").forEach((b) => {
      if (MKT_TABS.includes(b.dataset.tab)) return;
      b.addEventListener("click", () => {
        MKT_TABS.forEach((t) => { const el = $("#tab-" + t); if (el) el.classList.add("hide"); });
        document.querySelectorAll(".tabs button").forEach((x) => {
          if (MKT_TABS.includes(x.dataset.tab)) x.classList.remove("on");
        });
      });
    });
  }

  function showMktTab(which, btn) {
    // hide every core + marketing section, show ours
    CORE_TABS.forEach((t) => { const el = $("#tab-" + t); if (el) el.classList.add("hide"); });
    MKT_TABS.forEach((t) => { const el = $("#tab-" + t); if (el) el.classList.toggle("hide", t !== which); });
    document.querySelectorAll(".tabs button").forEach((x) => x.classList.remove("on"));
    btn.classList.add("on");
    const sb = $("#savebar"); if (sb) sb.classList.add("hide"); // marketing tabs never publish
    if (which === "contacts") loadContacts();
    if (which === "campaigns") { loadStatus(); loadCampaigns(); }
