    el.innerHTML = rows.map(campCard).join("");
  }
  function statusPill(s) {
    const c = { draft: "var(--slate)", scheduled: "var(--tide)", sending: "var(--tide2)", sent: "var(--ink)", paused: "#B4483A" }[s] || "var(--slate)";
    return `<span style="font-size:.68rem;letter-spacing:.08em;text-transform:uppercase;color:#fff;background:${c};padding:.15rem .55rem;border-radius:999px">${esc(s)}</span>`;
  }
  function campCard(c) {
    const editable = c.status === "draft" || c.status === "paused";
    return `<div class="panel" style="padding:1rem 1.1rem;margin-bottom:.8rem">
      <div style="display:flex;align-items:center;gap:.6rem;flex-wrap:wrap">
        <strong>${esc(c.name)}</strong> ${statusPill(c.status)}
        <span style="font-size:.72rem;color:var(--slate)">${c.channel === "sms" ? "Text" : "Email"}</span>
        <span style="margin-left:auto;font-size:.75rem;color:var(--slate)">
          sent ${fmt(c.cnt_sent)} · queued ${fmt(c.cnt_queued)} · failed ${fmt(c.cnt_failed)} · suppressed ${fmt(c.cnt_suppressed)}</span>
      </div>
      <div style="font-size:.82rem;color:var(--slate);margin-top:.5rem;white-space:pre-wrap">${esc((c.body || "").slice(0, 160))}${(c.body || "").length > 160 ? "…" : ""}</div>
      <div style="display:flex;gap:.5rem;margin-top:.7rem">
        <button class="btn sm ghost" data-open="${esc(c.id)}">${editable ? "Edit" : "View"}</button>
        ${c.status === "sending" || c.status === "scheduled" ? `<button class="btn sm ghost" data-pause="${esc(c.id)}">Pause</button>` : ""}
      </div></div>`;
  }

  function openCampaign(c) {
    const locked = c && !(c.status === "draft" || c.status === "paused");
    $("#cpTitle").textContent = c ? (locked ? "Campaign" : "Edit campaign") : "New campaign";
    $("#cpId").value = c ? c.id : "";
    $("#cpChannel").value = c ? c.channel : "sms";
    $("#cpName").value = c ? c.name : "";
    $("#cpSubject").value = c ? (c.subject || "") : "";
    $("#cpBody").value = c ? (c.body || "") : "";
    $("#cpSegment").value = c ? (c.segment || "") : "";
    $("#cpSchedule").value = "";
    $("#cpCount").textContent = "—";
    $("#cpErr").textContent = ""; $("#cpTestStatus").textContent = "";
    $("#cpDelete").classList.toggle("hide", !c);
    ["cpChannel", "cpName", "cpSubject", "cpBody", "cpSegment", "cpSchedule"].forEach((id) => { $("#" + id).disabled = locked; });
    $("#cpSaveDraft").classList.toggle("hide", locked);
    $("#cpSend").classList.toggle("hide", locked);
