      if (!to) { $("#cpTestStatus").textContent = "Enter a test phone or email."; return; }
      $("#cpTestStatus").textContent = "Sending test…";
      const r = await api("/api/admin/campaigns/" + id + "/test", { method: "POST", body: JSON.stringify({ to, name: "Adrian" }) });
      const d = await r.json().catch(() => ({}));
