        if (Number.isNaN(ts)) { $("#cpErr").textContent = "Invalid schedule time."; return; }
        const r = await api("/api/admin/campaigns/" + id + "/schedule", { method: "POST", body: JSON.stringify({ scheduled_at: ts }) });
        const d = await r.json().catch(() => ({}));
        if (!r.ok) { $("#cpErr").textContent = d.error || "Schedule failed."; return; }
        modal.classList.add("hide"); loadCampaigns();
        return;
