      // send now: fetch live recipient count, then require typed confirmation
      const channel = $("#cpChannel").value;
      const segment = $("#cpSegment").value.trim();
      const cr = await api(`/api/admin/campaigns/recipient-count?channel=${channel}&segment=${encodeURIComponent(segment)}`);
      const cd = await cr.json().catch(() => ({}));
      const n = cd.count != null ? cd.count : "?";
      if (channel === "sms" && quietHours) {
        $("#cpErr").textContent = "It's quiet hours (SMS only sends 9am–8pm ET). Schedule it instead.";
        return;
      }
      openConfirm(id, channel, n);
    });

    // confirm modal
    $("#cpConfirmCancel").addEventListener("click", () => $("#cpConfirm").classList.add("hide"));
    $("#cpConfirmGo").addEventListener("click", doSend);
    $("#cpConfirmInput").addEventListener("keydown", (e) => { if (e.key === "Enter") doSend(); });
  }

  let pendingSendId = null;
  function openConfirm(id, channel, n) {
    pendingSendId = id;
    $("#cpConfirmTitle").textContent = channel === "sms" ? "Confirm text blast" : "Confirm email send";
    $("#cpConfirmMsg").textContent = `This will ${channel === "sms" ? "text" : "email"} ${n} consenting contact${n === 1 ? "" : "s"} now. Suppressed and no-consent contacts are excluded automatically.`;
    $("#cpConfirmInput").value = ""; $("#cpConfirmErr").textContent = "";
    $("#cpConfirm").classList.remove("hide");
    $("#cpConfirmInput").focus();
  }
  async function doSend() {
    if ($("#cpConfirmInput").value.trim() !== "SEND") { $("#cpConfirmErr").textContent = 'Type SEND exactly to confirm.'; return; }
    const r = await api("/api/admin/campaigns/" + pendingSendId + "/send", { method: "POST", body: JSON.stringify({ confirm: "SEND" }) });
    const d = await r.json().catch(() => ({}));
    if (!r.ok) { $("#cpConfirmErr").textContent = d.error || "Send failed."; return; }
    $("#cpConfirm").classList.add("hide");
    $("#cpModal").classList.add("hide");
    loadCampaigns();
  }
})();
