// Email marketing pipeline for the adriancortez worker.
// Owns: Resend send pipeline, HMAC unsubscribe tokens, GET/POST /u/:token,
// List-Unsubscribe headers, bounce/complaint webhook, chunked cron send loop.
//
// Imported by src/marketing.js. Reuses ADMIN_KEY to sign unsubscribe tokens
// (same HMAC construction as worker.js hmac()), so no extra token secret is needed.

// ------------------------------------------------------------------ helpers
const enc = new TextEncoder();
const clean = (v, max = 500) => String(v ?? "").trim().slice(0, max);
const normalizeEmail = (v) => clean(v, 254).toLowerCase();
const isEmail = (v) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(v || "").trim());

// Server-side HTML escape — same char set as the admin panel's esc(). Applied to
// every piece of contact-controlled data ({{name}}) merged into an HTML body.
const escHtml = (v) =>
  String(v ?? "").replace(/[&<>"']/g, (c) =>
    ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c]));

// Header-injection guard: subjects / From values must never contain CR/LF.
const headerSafe = (v, max = 300) => clean(v, max).replace(/[\r\n]+/g, " ");

async function hmacHex(secret, msg) {
  const key = await crypto.subtle.importKey(
    "raw", enc.encode(secret), { name: "HMAC", hash: "SHA-256" }, false, ["sign"]
  );
  const sig = await crypto.subtle.sign("HMAC", key, enc.encode(msg));
  return [...new Uint8Array(sig)].map((b) => b.toString(16).padStart(2, "0")).join("");
}

function timingSafeEqual(a, b) {
  if (typeof a !== "string" || typeof b !== "string" || a.length !== b.length) return false;
  let out = 0;
  for (let i = 0; i < a.length; i++) out |= a.charCodeAt(i) ^ b.charCodeAt(i);
  return out === 0;
}

const b64url = (s) => btoa(s).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
const b64urlDecode = (s) => {
  s = s.replace(/-/g, "+").replace(/_/g, "/");
  while (s.length % 4) s += "=";
  return atob(s);
};

// PUBLIC_ORIGIN is REQUIRED for building unsubscribe links (cron has no request
// URL). Callers that send email must verify it is set; this just reads it.
const publicOrigin = (env) => clean(env.PUBLIC_ORIGIN);

// -------------------------------------------------------- unsubscribe tokens
// Token = b64url(payload) + "." + hmac(ADMIN_KEY, payload).
// payload = "e|<contactId>|<email>". Self-verifying, no DB storage, un-forgeable.
// Never expires — an unsubscribe link must work forever. Embeds the email so /u
// still suppresses even if the contact row was later deleted.
export async function makeUnsubToken(env, contactId, email) {
  const payload = `e|${contactId}|${normalizeEmail(email)}`;
  return `${b64url(payload)}.${await hmacHex(env.ADMIN_KEY, payload)}`;
}

async function parseUnsubToken(env, token) {
  if (!token || typeof token !== "string" || token.length > 2048) return null;
  const dot = token.lastIndexOf(".");
  if (dot < 1) return null;
  const rawPayload = token.slice(0, dot);
  const sig = token.slice(dot + 1);
  let payload; try { payload = b64urlDecode(rawPayload); } catch { return null; }
  if (!timingSafeEqual(sig, await hmacHex(env.ADMIN_KEY, payload))) return null;
  const parts = payload.split("|");
  if (parts[0] !== "e") return null;
  return { channel: "email", contactId: parts[1] || "", email: parts[2] || "" };
}

// ----------------------------------------------------------------- suppression
export async function suppressEmail(env, email, reason = "unsubscribe") {
  const norm = normalizeEmail(email);
  if (!norm) return;
  await env.DB.batch([
    env.DB.prepare(
      `INSERT INTO suppressions (email, phone, channel, reason, ts) VALUES (?1, '', 'email', ?2, ?3)`
    ).bind(norm, clean(reason, 120), Date.now()),
    env.DB.prepare(`UPDATE contacts SET consent_email=0 WHERE lower(email)=?1`).bind(norm),
  ]);
}

async function isEmailSuppressed(env, email) {
  const norm = normalizeEmail(email);
  if (!norm) return true;
  const r = await env.DB.prepare(
    `SELECT 1 FROM suppressions WHERE channel='email' AND lower(email)=?1 LIMIT 1`
  ).bind(norm).first();
  return !!r;
}

// ------------------------------------------------------------- segmentation
// Comma-wrapped tag substring match (tags stored as ",t1,t2,"). "" = everyone.
function tagFilter(tag) {
  const t = String(tag || "").trim().toLowerCase().replace(/\s+/g, "-");
  return t ? `,${t},` : "";
}

export async function countEmailRecipients(env, tag) {
  const t = tagFilter(tag);
  const sql = `
    SELECT COUNT(*) n FROM contacts c
     WHERE c.consent_email=1 AND c.email IS NOT NULL AND c.email!=''
       ${t ? "AND instr(lower(c.tags), ?1) > 0" : ""}
       AND NOT EXISTS (SELECT 1 FROM suppressions s
                        WHERE s.channel='email' AND lower(s.email)=lower(c.email))`;
  const row = t ? await env.DB.prepare(sql).bind(t).first() : await env.DB.prepare(sql).first();
  return row ? row.n : 0;
}

// Seed the sends queue for a campaign entering 'sending'. Only consented,
// non-suppressed, valid-email contacts in the segment get a 'queued' row; the
// send loop re-checks suppression at delivery time as the authoritative gate.
export async function seedEmailQueue(env, campaign) {
  const t = tagFilter(campaign.tag);
  const sql = `
    INSERT OR IGNORE INTO sends (campaign_id, contact_id, channel, status, provider_id, error, ts)
    SELECT ?1, c.id, 'email', 'queued', '', '', ?2
      FROM contacts c
     WHERE c.consent_email=1 AND c.email IS NOT NULL AND c.email!=''
       ${t ? "AND instr(lower(c.tags), ?3) > 0" : ""}
       AND NOT EXISTS (SELECT 1 FROM suppressions s
                        WHERE s.channel='email' AND lower(s.email)=lower(c.email))`;
  const stmt = env.DB.prepare(sql);
  await (t ? stmt.bind(campaign.id, Date.now(), t) : stmt.bind(campaign.id, Date.now())).run();
}

// ------------------------------------------------------------- Resend send
async function resendSend(env, { to, subject, html, text, unsubUrl }) {
  const from = headerSafe(env.EMAIL_FROM, 254); // e.g. "Adrian Cortez <adrian@mail.adriancortez.com>"
  const mailto = clean(env.UNSUB_MAILTO, 254);
  const listUnsub = mailto ? `<${unsubUrl}>, <mailto:${mailto}?subject=unsubscribe>` : `<${unsubUrl}>`;

  const res = await fetch("https://api.resend.com/emails", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${env.RESEND_API_KEY}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      from,
      to: [to],                       // bare address string — no name interpolation
      subject: headerSafe(subject),
      html,
      text,
      headers: {
        "List-Unsubscribe": listUnsub,
        "List-Unsubscribe-Post": "List-Unsubscribe=One-Click",
        "Precedence": "bulk",
      },
    }),
  });
  let data = null; try { data = await res.json(); } catch { /* non-JSON */ }
  if (!res.ok) return { ok: false, error: clean((data && (data.message || data.name)) || `resend ${res.status}`, 300) };
  return { ok: true, id: (data && data.id) || "" };
}

// Merge {{name}} (case/space tolerant). Returns escaped HTML + raw text variants.
function mergeBody(rawBody, name) {
  const nm = clean(name, 120) || "there";
  const textOut = String(rawBody).replace(/\{\{\s*name\s*\}\}/gi, nm);   // raw for text part
  const htmlOut = escHtml(textOut).replace(/\n/g, "<br>");               // escaped for HTML part
  return { htmlOut, textOut };
}

function buildEmailHtml({ bodyHtml, unsubUrl, fromName }) {
  const safeName = escHtml(fromName || "Adrian Cortez");
  return `<!DOCTYPE html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="margin:0;background:#F3F1EB;font-family:Archivo,Helvetica,Arial,sans-serif;color:#0E141C">
<div style="max-width:560px;margin:0 auto;padding:28px 22px">
  <div style="font-family:Georgia,'Times New Roman',serif;font-weight:700;font-size:20px;color:#0E141C;margin-bottom:20px">
    ${safeName}<span style="color:#1E7A6A">.</span>
  </div>
  <div style="background:#FCFBF8;border:1px solid rgba(14,20,28,.14);padding:26px 24px;font-size:15px;line-height:1.6">
    ${bodyHtml}
  </div>
  <div style="margin-top:20px;font-size:12px;line-height:1.5;color:#5A626C">
    Adrian Cortez &middot; SERHANT. &middot; Brickell, Miami. You're receiving this because you
    connected with Adrian about real estate. <a href="${escHtml(unsubUrl)}" style="color:#14594E">Unsubscribe</a> anytime.
  </div>
</div></body></html>`;
}

function buildEmailText({ bodyText, unsubUrl, fromName }) {
  return `${bodyText}\n\n— ${fromName || "Adrian Cortez"}, SERHANT.\n\nUnsubscribe: ${unsubUrl}`;
}

// ---------------------------------------------------------------- send loop
// Process at most EMAIL_CHUNK email sends across the currently-sending campaigns
// per cron tick. Each Resend call is one external subrequest; keeping the total
// under 45 stays below the Workers Free-plan 50/invocation ceiling with margin.
const EMAIL_CHUNK = 45;

export async function processEmailQueue(env) {
  const origin = publicOrigin(env);
  if (!origin) return; // fail closed — never emit broken unsubscribe links

  // Oldest sending campaign first; one campaign's chunk per tick keeps the
  // per-invocation external-subrequest count bounded.
  const campaign = await env.DB.prepare(
    `SELECT * FROM campaigns WHERE channel='email' AND status='sending' ORDER BY scheduled_at LIMIT 1`
  ).first();
  if (!campaign) return;

  const { results: queue } = await env.DB.prepare(
    `SELECT s.id AS send_id, c.id AS contact_id, c.name, c.email, c.consent_email
       FROM sends s JOIN contacts c ON c.id = s.contact_id
      WHERE s.campaign_id=?1 AND s.channel='email' AND s.status='queued'
      ORDER BY s.id LIMIT ?2`
  ).bind(campaign.id, EMAIL_CHUNK).all();

  if (!queue || queue.length === 0) {
    await env.DB.prepare(`UPDATE campaigns SET status='sent' WHERE id=?1 AND status='sending'`)
      .bind(campaign.id).run();
    return;
  }

  const fromName = clean(env.EMAIL_FROM_NAME) || "Adrian Cortez";
  const updates = [];

  for (const row of queue) {
    const email = normalizeEmail(row.email);
    if (!isEmail(email)) {
      updates.push(env.DB.prepare(`UPDATE sends SET status='failed', error='invalid email', ts=?2 WHERE id=?1`)
        .bind(row.send_id, Date.now()));
      continue;
    }
    // SEND-TIME re-gate: consent may have been revoked or the address suppressed
    // after the campaign was queued. This is the authoritative check.
    if (row.consent_email !== 1 || await isEmailSuppressed(env, email)) {
      updates.push(env.DB.prepare(`UPDATE sends SET status='suppressed', error=?2, ts=?3 WHERE id=?1`)
        .bind(row.send_id, row.consent_email !== 1 ? "no consent" : "suppressed", Date.now()));
      continue;
    }

    const token = await makeUnsubToken(env, row.contact_id, email);
    const unsubUrl = `${origin}/u/${encodeURIComponent(token)}`;
    const { htmlOut, textOut } = mergeBody(campaign.body, row.name);

    const r = await resendSend(env, {
      to: email,
      subject: campaign.subject,
      html: buildEmailHtml({ bodyHtml: htmlOut, unsubUrl, fromName }),
      text: buildEmailText({ bodyText: textOut, unsubUrl, fromName }),
      unsubUrl,
    });

    updates.push(r.ok
      ? env.DB.prepare(`UPDATE sends SET status='sent', provider_id=?2, error='', ts=?3 WHERE id=?1`)
          .bind(row.send_id, r.id, Date.now())
      : env.DB.prepare(`UPDATE sends SET status='failed', error=?2, ts=?3 WHERE id=?1`)
          .bind(row.send_id, r.error, Date.now()));
  }

  if (updates.length) await env.DB.batch(updates);

  // If the chunk was not full, the queue is drained — mark sent.
  if (queue.length < EMAIL_CHUNK) {
    await env.DB.prepare(`UPDATE campaigns SET status='sent' WHERE id=?1 AND status='sending'`)
      .bind(campaign.id).run();
  }
}

// ------------------------------------------------------------------ test send
export async function sendTestEmail(env, campaign, toEmail) {
  const origin = publicOrigin(env);
  if (!origin) return { ok: false, error: "PUBLIC_ORIGIN not set" };
  const to = normalizeEmail(toEmail);
  if (!isEmail(to)) return { ok: false, error: "invalid test address" };
  const fromName = clean(env.EMAIL_FROM_NAME) || "Adrian Cortez";
  const token = await makeUnsubToken(env, "test", to);
  const unsubUrl = `${origin}/u/${encodeURIComponent(token)}`;
  const { htmlOut, textOut } = mergeBody(campaign.body, "Adrian");
  return resendSend(env, {
    to,
    subject: `[TEST] ${headerSafe(campaign.subject)}`,
    html: buildEmailHtml({ bodyHtml: htmlOut, unsubUrl, fromName }),
    text: buildEmailText({ bodyText: textOut, unsubUrl, fromName }),
    unsubUrl,
  });
}

// ---------------------------------------------------- public unsubscribe route
// GET /u/:token  -> browser click, styled confirmation page.
// POST /u/:token -> RFC 8058 one-click (List-Unsubscribe-Post target is this URL).
export async function handleUnsubscribe(req, env, url) {
  const m = url.pathname.match(/^\/u\/([^/]+)$/);
  if (!m) return null;
  const token = decodeURIComponent(m[1]);
  const parsed = await parseUnsubToken(env, token);

  if (!parsed) {
    if (req.method === "POST") return new Response("invalid", { status: 400 });
    return unsubPage("This link isn't valid",
      "The unsubscribe link is malformed. Reply to any email and we'll remove you.", false);
  }

  await suppressEmail(env, parsed.email, "unsubscribe"); // idempotent

  if (req.method === "POST") {
    return new Response("Unsubscribed", { status: 200, headers: { "Cache-Control": "no-store" } });
  }
  return unsubPage("You're unsubscribed",
    `${escHtml(parsed.email)} won't receive marketing emails from Adrian Cortez anymore. This takes effect immediately.`,
    true);
}

