  return new Response(body, {
    status: ok ? 200 : 400,
    headers: { "Content-Type": "text/html; charset=utf-8", "Cache-Control": "no-store" },
  });
}

// ---------------------------------------- Resend bounce/complaint webhook (Svix)
// POST /api/hooks/resend. Auto-suppress hard bounces + spam complaints so we stop
// mailing addresses that hurt deliverability. Verifies the Svix signature that
// Resend sends. Set RESEND_WEBHOOK_SECRET (whsec_...) and point the Resend
// webhook at PUBLIC_ORIGIN + "/api/hooks/resend".
export async function handleResendWebhook(req, env) {
  const raw = await req.text();

  if (env.RESEND_WEBHOOK_SECRET) {
    const id = req.headers.get("svix-id") || "";
    const ts = req.headers.get("svix-timestamp") || "";
    const sigHeader = req.headers.get("svix-signature") || "";
    if (!id || !ts || !sigHeader) return new Response("missing signature", { status: 400 });

    // Svix: secret is base64 after the "whsec_" prefix; sign base64 of the HMAC
    // over `${id}.${ts}.${body}`; header carries space-delimited "v1,<b64sig>".
    const secretB64 = env.RESEND_WEBHOOK_SECRET.replace(/^whsec_/, "");
    let keyBytes; try { keyBytes = Uint8Array.from(atob(secretB64), (c) => c.charCodeAt(0)); }
    catch { return new Response("bad secret", { status: 500 }); }
    const key = await crypto.subtle.importKey(
      "raw", keyBytes, { name: "HMAC", hash: "SHA-256" }, false, ["sign"]
    );
    const mac = await crypto.subtle.sign("HMAC", key, enc.encode(`${id}.${ts}.${raw}`));
    const expected = btoa(String.fromCharCode(...new Uint8Array(mac)));
    const ok = sigHeader.split(" ").some((part) => {
      const v = part.startsWith("v1,") ? part.slice(3) : part;
      return timingSafeEqual(v, expected);
    });
    if (!ok) return new Response("forbidden", { status: 403 });
  }

  let event; try { event = JSON.parse(raw); } catch { return new Response("bad json", { status: 400 }); }
  const type = event && event.type;
  const to = event && event.data && (event.data.to || event.data.email_to);
  const email = Array.isArray(to) ? to[0] : to;
  if (!email) return new Response("ok", { status: 200 });

  if (type === "email.bounced") {
    const bt = (event.data.bounce && event.data.bounce.type) || "";
    if (bt === "permanent" || bt === "hard") await suppressEmail(env, email, "hard_bounce");
  } else if (type === "email.complained") {
    await suppressEmail(env, email, "spam_complaint");
  }
  return new Response("ok", { status: 200 });
}
=== END FILE ===

