-- adriancortez-marketing D1 schema (binding DB). SHARED by the email and SMS
-- sections — both channels read/write these exact tables and columns.
-- Apply: wrangler d1 execute adriancortez-marketing --file=migrations/0001_marketing.sql --remote

CREATE TABLE IF NOT EXISTS contacts (
  id            TEXT PRIMARY KEY,
  name          TEXT NOT NULL DEFAULT '',
  phone         TEXT NOT NULL DEFAULT '',      -- E.164, e.g. +13055551234
  email         TEXT NOT NULL DEFAULT '',      -- lowercased
  tags          TEXT NOT NULL DEFAULT '',      -- ,t1,t2, comma-wrapped for substring match
  consent_sms   INTEGER NOT NULL DEFAULT 0,    -- 0/1
  consent_email INTEGER NOT NULL DEFAULT 0,    -- 0/1
  source        TEXT NOT NULL DEFAULT '',      -- manual | csv | lead-inbox
  notes         TEXT NOT NULL DEFAULT '',
  created       INTEGER NOT NULL               -- epoch ms
);
CREATE INDEX IF NOT EXISTS idx_contacts_email         ON contacts (email);
CREATE INDEX IF NOT EXISTS idx_contacts_phone         ON contacts (phone);
CREATE INDEX IF NOT EXISTS idx_contacts_consent_email ON contacts (consent_email);
CREATE INDEX IF NOT EXISTS idx_contacts_consent_sms   ON contacts (consent_sms);

CREATE TABLE IF NOT EXISTS campaigns (
  id           TEXT PRIMARY KEY,
  channel      TEXT NOT NULL CHECK (channel IN ('sms','email')),
  name         TEXT NOT NULL DEFAULT '',
  subject      TEXT NOT NULL DEFAULT '',       -- email only
  body         TEXT NOT NULL DEFAULT '',       -- supports {{name}} merge
  tag          TEXT NOT NULL DEFAULT '',       -- segment filter ('' = everyone)
  status       TEXT NOT NULL DEFAULT 'draft'
                 CHECK (status IN ('draft','scheduled','sending','sent','paused')),
  scheduled_at INTEGER,                        -- epoch ms, NULL until scheduled/sent
  created      INTEGER NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_campaigns_status ON campaigns (channel, status);

CREATE TABLE IF NOT EXISTS sends (
  id          INTEGER PRIMARY KEY AUTOINCREMENT,
  campaign_id TEXT NOT NULL,
  contact_id  TEXT NOT NULL,
  channel     TEXT NOT NULL CHECK (channel IN ('sms','email')),
  status      TEXT NOT NULL DEFAULT 'queued'
                CHECK (status IN ('queued','sent','delivered','failed','suppressed')),
  provider_id TEXT NOT NULL DEFAULT '',        -- Resend / Twilio message id
  error       TEXT NOT NULL DEFAULT '',
  ts          INTEGER NOT NULL                 -- epoch ms (INTEGER everywhere)
);
CREATE INDEX IF NOT EXISTS idx_sends_campaign ON sends (campaign_id, status);
CREATE UNIQUE INDEX IF NOT EXISTS idx_sends_unique ON sends (campaign_id, contact_id, channel);

CREATE TABLE IF NOT EXISTS suppressions (
  id      INTEGER PRIMARY KEY AUTOINCREMENT,
  email   TEXT NOT NULL DEFAULT '',            -- lowercased ('' for sms rows)
  phone   TEXT NOT NULL DEFAULT '',            -- E.164   ('' for email rows)
  channel TEXT NOT NULL CHECK (channel IN ('sms','email')),
  reason  TEXT NOT NULL DEFAULT '',
  ts      INTEGER NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_suppress_email ON suppressions (channel, email);
CREATE INDEX IF NOT EXISTS idx_suppress_phone ON suppressions (channel, phone);
