          <button class="btn sm ghost" id="mkImportCsv" type="button">CSV import</button>
          <button class="btn sm solid" id="mkAddContact" type="button">+ Contact</button>
        </div>
        <div id="mkContactList" class="mk-empty">Loading…</div>
      </div>`;
  }

  function contactRow(c) {
    const tags = tagsToArray(c.tags);
    const sms = c.consent_sms ? '<span class="mk-flag on">SMS ✓</span>' : '<span class="mk-flag off">SMS ✕</span>';
    const email = c.consent_email ? '<span class="mk-flag on">Email ✓</span>' : '<span class="mk-flag off">Email ✕</span>';
    const phoneLink = c.phone ? `<a href="tel:${esc(c.phone)}">${esc(fmtPhone(c.phone))}</a>` : "";
    const emailLink = c.email ? `<a href="mailto:${esc(c.email)}">${esc(c.email)}</a>` : "";
    const contactBits = [phoneLink, emailLink].filter(Boolean).join(" · ");
    return `
      <div class="mk-row" data-id="${esc(c.id)}">
        <div>
          <div class="who">${esc(c.name || "(no name)")}</div>
          <div class="meta">${contactBits || '<span class="mk-empty">no phone or email</span>'}</div>
          <div class="meta">${sms} ${email}${c.source ? " · " + esc(c.source) : ""}</div>
        </div>
        <div class="acts">
          <button class="btn sm ghost" data-mk="edit" data-id="${esc(c.id)}" type="button">Edit</button>
          <button class="btn sm danger" data-mk="del" data-id="${esc(c.id)}" type="button">Delete</button>
        </div>
        ${tags.length ? `<div class="mk-tags">${tags.map((t) => `<span class="chip">${esc(t)}</span>`).join("")}</div>` : ""}
      </div>`;
  }

  function renderContacts() {
    const q = state.contactQuery.trim().toLowerCase();
    let list = state.contacts;
    if (q) {
      list = list.filter((c) => {
        const hay = [c.name, c.phone, c.email, ...tagsToArray(c.tags)].join(" ").toLowerCase();
        return hay.includes(q);
      });
    }
    const badge = $("#mkContactCount");
    if (badge) {
      badge.textContent = state.contacts.length;
      badge.classList.toggle("hide", !state.contacts.length);
    }
    const host = $("#mkContactList");
    host.className = "";
    if (!list.length) {
      host.innerHTML = state.contacts.length
        ? '<p class="mk-empty">No contacts match that search.</p>'
        : '<p class="mk-empty">No contacts yet. Add one, import a CSV, or pull from the lead inbox.</p>';
      return;
    }
    host.innerHTML = list.map(contactRow).join("");
  }

  async function loadContacts() {
    const r = await api("/api/admin/contacts");
    if (!r.ok) { $("#mkContactList").innerHTML = '<p class="mk-empty">Could not load contacts.</p>'; return; }
    const data = await r.json();
    state.contacts = Array.isArray(data) ? data : data.contacts || [];
    const tagset = new Set();
    state.contacts.forEach((c) => tagsToArray(c.tags).forEach((t) => tagset.add(t)));
    state.allTags = [...tagset].sort();
    renderContacts();
  }

  function wireContacts(root) {
    root.addEventListener("input", (e) => {
      if (e.target.id !== "mkContactSearch") return;
      state.contactQuery = e.target.value;
      renderContacts();
    });
    root.addEventListener("click", async (e) => {
      const t = e.target;
      if (t.id === "mkAddContact") return openContactEditor({});
      if (t.id === "mkImportLeads") return importFromLeads();
      if (t.id === "mkImportCsv") return openCsvImport();
      const b = t.closest("button[data-mk]");
      if (!b) return;
      const id = b.dataset.id;
      const c = state.contacts.find((x) => String(x.id) === String(id));
      if (b.dataset.mk === "edit") return openContactEditor(c || { id });
      if (b.dataset.mk === "del") {
        if (!confirm(`Delete ${c ? c.name || "this contact" : "this contact"}? This also removes them from the CRM.`)) return;
        const r = await api(`/api/admin/contacts/${encodeURIComponent(id)}`, { method: "DELETE" });
        if (r.ok) { toast("Contact deleted."); loadContacts(); } else toast("Delete failed.", true);
      }
    });
  }

