            <label class="mk-check"><input type="checkbox" id="mkC_emailok" ${c.consent_email ? "checked" : ""}> Emails OK</label>
          </div>
        </div>
        <div class="full"><label for="mkC_notes">Notes</label><textarea id="mkC_notes" rows="2">${esc(c.notes)}</textarea></div>
