    $("#mkC_save").addEventListener("click", async () => {
      const name = $("#mkC_name").value.trim();
      const phoneRaw = $("#mkC_phone").value.trim();
      const email = $("#mkC_email").value.trim();
      const phone = phoneRaw ? normPhone(phoneRaw) : "";
      if (!name) return setErr("Name is required.");
      if (!phone && !email) return setErr("Add a phone or an email.");
      if (email && !/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) return setErr("That email doesn't look right.");
      if (phoneRaw && !/^\+\d{8,15}$/.test(phone)) return setErr("Phone must be a valid number (E.164, +1 default).");
      const payload = {
        id: c.id,
        name, phone, email,
        tags: tagsToArray($("#mkC_tags").value),
        source: $("#mkC_source").value.trim() || c.source || "admin",
        notes: $("#mkC_notes").value.trim(),
        consent_sms: $("#mkC_sms").checked ? 1 : 0,
        consent_email: $("#mkC_emailok").checked ? 1 : 0,
      };
      const r = await api(
        isNew ? "/api/admin/contacts" : `/api/admin/contacts/${encodeURIComponent(c.id)}`,
        { method: isNew ? "POST" : "PUT", body: JSON.stringify(payload) }
      );
      if (r.ok) { modal.close(); toast(isNew ? "Contact added." : "Contact saved."); loadContacts(); }
      else { const e = await r.json().catch(() => ({})); setErr(e.error || "Save failed."); }
    });
  }

