  // ---- CSV import (paste or file) ----
  function openCsvImport() {
    const modal = buildModal(`
      <h2>CSV import</h2>
      <p style="font-size:.9rem">Header row required. Recognized columns: <b>name, phone, email, tags, source, notes, consent_sms, consent_email</b>. Consent columns accept yes/no/true/false/1/0. Missing consent defaults to off.</p>
      <div class="mk-tools" style="margin:.8rem 0 .4rem">
        <input type="file" id="mkCsvFile" accept=".csv,text/csv" style="width:auto">
      </div>
      <label for="mkCsvText">…or paste rows</label>
      <textarea id="mkCsvText" rows="7" placeholder="name,phone,email,tags,consent_sms&#10;Jane Doe,(305) 555-0100,jane@email.com,buyer;brickell,yes"></textarea>
      <label class="mk-check" style="margin-top:.6rem"><input type="checkbox" id="mkCsvDedupe" checked> Skip duplicates (by phone or email)</label>
      <div class="warnline" id="mkCsv_err"></div>
      <p class="mk-hint" id="mkCsv_preview" style="margin:.4rem 0 0"></p>
      <div class="modacts">
        <button class="btn ghost" data-close type="button">Cancel</button>
        <button class="btn solid" id="mkCsv_go" type="button">Import</button>
      </div>
    `, true);
    const fileInput = $("#mkCsvFile");
    const textInput = $("#mkCsvText");
    const preview = () => {
      const rows = parseCsv(textInput.value);
      $("#mkCsv_preview").textContent = rows.length ? `${rows.length} valid row${rows.length === 1 ? "" : "s"} ready.` : "";
    };
    fileInput.addEventListener("change", () => {
      const f = fileInput.files && fileInput.files[0];
      if (!f) return;
      if (f.size > 2 * 1024 * 1024) { $("#mkCsv_err").textContent = "File too large (max 2MB)."; return; }
      const reader = new FileReader();
      reader.onload = () => { textInput.value = String(reader.result || ""); preview(); };
      reader.readAsText(f);
    });
    textInput.addEventListener("input", preview);
    $("#mkCsv_go").addEventListener("click", async () => {
      const rows = parseCsv(textInput.value);
      if (!rows.length) { $("#mkCsv_err").textContent = "No valid rows found. Check the header row and columns."; return; }
      const btn = $("#mkCsv_go");
      btn.disabled = true; btn.textContent = "Importing…";
      const r = await api("/api/admin/contacts/import", {
        method: "POST",
        body: JSON.stringify({ contacts: rows, dedupe: $("#mkCsvDedupe").checked }),
      });
      if (r.ok) {
        const res = await r.json().catch(() => ({}));
        modal.close();
        const added = res.added ?? res.imported ?? rows.length;
        const skipped = res.skipped ?? 0;
        toast(`Imported ${added}${skipped ? `, ${skipped} skipped` : ""}.`);
        loadContacts();
      } else {
        btn.disabled = false; btn.textContent = "Import";
        const e = await r.json().catch(() => ({}));
        $("#mkCsv_err").textContent = e.error || "Import failed.";
      }
    });
  }

  // RFC-4180-ish CSV parser: quoted fields, escaped "", commas + newlines inside quotes
  function parseCsv(text) {
    const src = String(text || "").replace(/\r\n?/g, "\n").trim();
    if (!src) return [];
    const records = [];
    let field = "", row = [], inQ = false;
    for (let i = 0; i < src.length; i++) {
      const ch = src[i];
      if (inQ) {
        if (ch === '"') {
          if (src[i + 1] === '"') { field += '"'; i++; } else inQ = false;
        } else field += ch;
      } else if (ch === '"') inQ = true;
      else if (ch === ",") { row.push(field); field = ""; }
      else if (ch === "\n") { row.push(field); records.push(row); row = []; field = ""; }
      else field += ch;
    }
    row.push(field);
    records.push(row);
    if (records.length < 2) return [];
    const header = records[0].map((h) => h.trim().toLowerCase());
    const idx = (name) => header.indexOf(name);
    const iName = idx("name"), iPhone = idx("phone"), iEmail = idx("email"),
      iTags = idx("tags"), iSource = idx("source"), iNotes = idx("notes"),
      iSms = idx("consent_sms"), iEmailC = idx("consent_email");
    const truthy = (v) => /^(1|y|yes|true|t)$/i.test(String(v || "").trim());
    const cell = (cells, i) => (i >= 0 ? String(cells[i] || "").trim() : "");
    const out = [];
    for (let r = 1; r < records.length; r++) {
      const cells = records[r];
      if (!cells.length || cells.every((c) => !String(c).trim())) continue;
      const name = cell(cells, iName);
      const phoneRaw = cell(cells, iPhone);
      const email = cell(cells, iEmail);
      const phone = phoneRaw ? normPhone(phoneRaw) : "";
      if (!phone && !email) continue; // need a channel
      out.push({
        name: name || "(no name)",
        phone, email,
        tags: iTags >= 0 ? tagsToArray(cell(cells, iTags).replace(/;/g, ",")) : [],
        source: cell(cells, iSource) || "csv",
        notes: cell(cells, iNotes),
        consent_sms: iSms >= 0 && truthy(cells[iSms]) ? 1 : 0,
        consent_email: iEmailC >= 0 && truthy(cells[iEmailC]) ? 1 : 0,
      });
    }
    return out;
  }

