  function campaignsMarkup() {
    return `
      <div class="panel">
        <h2>Campaigns</h2>
        <p class="mk-hint">Text and email the sphere. Recipients are filtered by tag and by consent — opted-out people never receive a send. SMS only goes out 9am–8pm ET; sends queued outside that window wait.</p>
        <div class="mk-tools">
          <button class="btn sm solid" id="mkNewCampaign" type="button">+ New campaign</button>
        </div>
        <div id="mkCampaignList" class="mk-empty">Loading…</div>
      </div>
      <div class="panel hide" id="mkComposerPanel">
        <h2 id="mkComposerTitle">New campaign</h2>
        <div id="mkComposer"></div>
      </div>`;
