  function campaignCard(c) {
    const s = c.stats || {};
    const pill = (label, val, cls) => `<span class="mk-stat ${cls || ""}">${esc(label)} <b>${esc(String(val ?? 0))}</b></span>`;
    const canEdit = c.status === "draft" || c.status === "scheduled" || c.status === "paused";
    const canPause = c.status === "scheduled" || c.status === "sending";
    const canResume = c.status === "paused";
    return `
      <div class="mk-row" data-id="${esc(c.id)}">
        <div>
          <div class="who">${esc(c.name || "(untitled)")} <span class="mk-status ${esc(c.status)}">${esc(c.status)}</span></div>
          <div class="meta"><span class="mk-chan">${esc(String(c.channel || "").toUpperCase())}</span>${c.subject ? " · " + esc(c.subject) : ""}${c.tag_filter ? " · tag: " + esc(c.tag_filter) : " · all consented"}</div>
          ${c.scheduled_at ? `<div class="meta">Scheduled ${esc(fmtDateTime(c.scheduled_at))}</div>` : ""}
          <div class="mk-stats">
            ${pill("recipients", s.total, "")}
            ${pill("sent", s.sent, "sent")}
            ${pill("queued", s.queued, "")}
            ${pill("failed", s.failed, "failed")}
            ${pill("suppressed", s.suppressed, "suppressed")}
          </div>
        </div>
        <div class="acts">
          ${canEdit ? `<button class="btn sm ghost" data-mk="editc" data-id="${esc(c.id)}" type="button">Edit</button>` : ""}
          ${canPause ? `<button class="btn sm ghost" data-mk="pause" data-id="${esc(c.id)}" type="button">Pause</button>` : ""}
          ${canResume ? `<button class="btn sm ghost" data-mk="resume" data-id="${esc(c.id)}" type="button">Resume</button>` : ""}
          ${c.status === "draft" ? `<button class="btn sm danger" data-mk="delc" data-id="${esc(c.id)}" type="button">Delete</button>` : ""}
        </div>
      </div>`;
  }

  function renderCampaigns() {
    const host = $("#mkCampaignList");
    host.className = "";
    if (!state.campaigns.length) {
      host.innerHTML = '<p class="mk-empty">No campaigns yet. Create one to text or email the sphere.</p>';
      return;
    }
    host.innerHTML = state.campaigns.map(campaignCard).join("");
  }

  async function loadCampaigns() {
    const r = await api("/api/admin/campaigns");
    if (!r.ok) { $("#mkCampaignList").innerHTML = '<p class="mk-empty">Could not load campaigns.</p>'; return; }
    const data = await r.json();
    state.campaigns = Array.isArray(data) ? data : data.campaigns || [];
    renderCampaigns();
    // ensure the tag universe is warm for the composer even if Contacts wasn't opened
    if (!state.allTags.length) {
      const cr = await api("/api/admin/contacts");
      if (cr.ok) {
        const cs = await cr.json();
        const arr = Array.isArray(cs) ? cs : cs.contacts || [];
        const tagset = new Set();
        arr.forEach((c) => tagsToArray(c.tags).forEach((t) => tagset.add(t)));
        state.allTags = [...tagset].sort();
      }
    }
  }

  function wireCampaigns(root) {
    root.addEventListener("click", async (e) => {
      if (e.target.id === "mkNewCampaign") return openComposer({});
      const b = e.target.closest("button[data-mk]");
      if (!b || !b.closest("#mkCampaignList")) return;
      const id = b.dataset.id;
      const c = state.campaigns.find((x) => String(x.id) === String(id));
      const act = b.dataset.mk;
      if (act === "editc") return openComposer(c || { id });
      if (act === "delc") {
        if (!confirm("Delete this draft campaign?")) return;
        const r = await api(`/api/admin/campaigns/${encodeURIComponent(id)}`, { method: "DELETE" });
        r.ok ? (toast("Draft deleted."), loadCampaigns()) : toast("Delete failed.", true);
      }
      if (act === "pause") {
        const r = await api(`/api/admin/campaigns/${encodeURIComponent(id)}/pause`, { method: "POST" });
        r.ok ? (toast("Campaign paused."), loadCampaigns()) : toast("Pause failed.", true);
      }
      if (act === "resume") {
        const r = await api(`/api/admin/campaigns/${encodeURIComponent(id)}/resume`, { method: "POST" });
        r.ok ? (toast("Campaign resumed."), loadCampaigns()) : toast("Resume failed.", true);
      }
    });
  }

  function openComposer(c) {
