    const channel = c.channel || "sms";
    const tagOptions = '<option value="">— everyone consented —</option>' +
      state.allTags.map((t) => `<option value="${esc(t)}" ${c.tag_filter === t ? "selected" : ""}>${esc(t)}</option>`).join("");

    $("#mkComposer").innerHTML = `
      <div class="mk-grid2">
        <div>
          <label for="mkK_channel">Channel</label>
          <select id="mkK_channel">
            <option value="sms" ${channel === "sms" ? "selected" : ""}>Text (SMS)</option>
