        <div>
          <div class="lbl" id="mkK_recipLbl">recipients will receive this</div>
          <div class="sub" id="mkK_recipNote">Filtered by tag and consent. Opted-out and no-consent contacts are excluded automatically.</div>
        </div>
      </div>

      <div class="mk-inline">
        <div>
          <label for="mkK_testTo">Test send to</label>
          <input id="mkK_testTo" value="${esc(channel === "email" ? ADRIAN.email : ADRIAN.phone)}">
        </div>
