        <button class="btn solid" id="mkK_sendNow" type="button">Send now…</button>
      </div>
      <p class="mk-note" id="mkK_channelNote"></p>
    `;

    const chanSel = $("#mkK_channel");
    const bodyEl = $("#mkK_body");
    const subjectWrap = $("#mkK_subjectWrap");
    const testTo = $("#mkK_testTo");

    function syncChannel() {
      const ch = chanSel.value;
      subjectWrap.classList.toggle("hide", ch !== "email");
