// marketing-security.js — single audited home for the marketing backend's
// security + compliance invariants. src/marketing.js (the router + runCron) and
// the admin UI MUST call through the helpers here rather than re-implementing
// consent checks, signature verification, phone normalization, escaping, quiet
// hours, token signing, test-send restriction, or rate limiting. If a guarantee
// is not enforced here at the point it matters, treat it as UNENFORCED.
//
// Ground-truth alignment (verified against the live repo, 2026-07-15):
//   - `contacts` ALREADY EXISTS (migrations/0002_crm.sql + src/crm.js). Its id
//     is a UUID string; consent flags are consent_sms / consent_email; the phone
//     is stored via crm.js `normPhone`. This module RE-USES normPhone so
//     suppression matching and CRM storage never diverge (a mismatched format is
//     a compliance leak).
//   - The worker's isAdmin() uses `===` on the bearer key and the session HMAC
//     (worker.js lines 34, 44) — timing-unsafe. This module ships a constant-time
//     isAdmin() the router uses instead; it keeps the SAME cookie name (ac_admin)
//     and token shape (exp.hmac) so live sessions keep working.
//   - Marketing tables (campaigns/sends/suppressions) use `ts` = INTEGER epoch
//     ms (Date.now()). The pre-existing contacts.created stays an ISO string;
//     the two conventions never mix within one table.
//
// No npm deps. Web Crypto + fetch only.

import { normPhone } from "./crm.js";

// ---------------------------------------------------------------------------
// 0. Constant-time comparison. Used for admin key, session HMAC, Twilio sig,
//    and unsubscribe token sig. Never use === on a secret or a signature.
// ---------------------------------------------------------------------------
export function timingSafeEqual(a, b) {
  const ab = typeof a === "string" ? new TextEncoder().encode(a) : a;
  const bb = typeof b === "string" ? new TextEncoder().encode(b) : b;
  // Seed diff with the length delta so unequal-length inputs always fail, then
  // iterate the max length (no early return) to avoid leaking length via timing.
  const len = Math.max(ab.length, bb.length);
  let diff = ab.length ^ bb.length;
  for (let i = 0; i < len; i++) diff |= (ab[i] ?? 0) ^ (bb[i] ?? 0);
  return diff === 0;
}

async function hmacHex(secret, msg) {
  const key = await crypto.subtle.importKey(
    "raw", new TextEncoder().encode(secret),
    { name: "HMAC", hash: "SHA-256" }, false, ["sign"]
  );
  const sig = await crypto.subtle.sign("HMAC", key, new TextEncoder().encode(msg));
  return [...new Uint8Array(sig)].map((b) => b.toString(16).padStart(2, "0")).join("");
}

// ---------------------------------------------------------------------------
// 1. Admin auth — constant-time replacement for the worker's isAdmin(). Same
//    cookie name + token shape (exp.hmac signed with ADMIN_KEY) as worker.js, so
//    sessions issued by the existing /api/admin/login keep working unchanged;
//    the only change is that every secret compare is timing-safe and the check
//    fails closed if ADMIN_KEY is missing or too short.
// ---------------------------------------------------------------------------
const COOKIE = "ac_admin";

function readCookie(req, name) {
  const m = (req.headers.get("Cookie") || "").match(
    new RegExp(`(?:^|;\\s*)${name}=([^;]+)`)
  );
  return m ? m[1] : null;
}

async function validSessionToken(env, token) {
  if (!token || typeof token !== "string") return false;
  const dot = token.indexOf(".");
  if (dot < 1) return false;
  const exp = token.slice(0, dot);
  const sig = token.slice(dot + 1);
  const expNum = Number(exp);
  if (!Number.isFinite(expNum) || expNum < Date.now()) return false;
  const expect = await hmacHex(env.ADMIN_KEY, exp);
  return timingSafeEqual(sig, expect);
}

// The one authority for "is this an authenticated admin request". The marketing
// router awaits this and 401s on false, BEFORE parsing any body or touching D1.
export async function isAdmin(req, env) {
  if (!env.ADMIN_KEY || String(env.ADMIN_KEY).length < 16) return false; // fail closed
  const bearer = (req.headers.get("Authorization") || "").replace(/^Bearer\s+/i, "");
  if (bearer && timingSafeEqual(bearer, env.ADMIN_KEY)) return true;
  return validSessionToken(env, readCookie(req, COOKIE));
}

// Guard helper: returns a 401 Response if not admin, else null.
export async function requireAdmin(req, env) {
  if (await isAdmin(req, env)) return null;
  return secJson({ error: "unauthorized" }, 401);
}

// ---------------------------------------------------------------------------
// 2. JSON + escaping helpers. secJson mirrors worker.js (no-store everywhere).
//    esc() is byte-identical to the admin page's inline esc() so the UI and the
//    server agree. escXml() is the minimal set for TwiML bodies (& < > only).
//    stripCsvFormula() defuses spreadsheet formula injection on ANY CSV export.
// ---------------------------------------------------------------------------
export const secJson = (data, status = 200, headers = {}) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json", "Cache-Control": "no-store", ...headers },
  });

export function esc(v) {
  return String(v ?? "").replace(/[&<>"']/g, (c) =>
    ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c])
  );
}

export function escXml(v) {
  return String(v ?? "").replace(/[&<>]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[c]));
}

// Neutralize a leading formula trigger so a contact named =HYPERLINK(...) can't
// execute if a list is ever exported to CSV and opened in Excel/Sheets.
export function stripCsvFormula(v) {
  const s = String(v ?? "");
  return /^[=+\-@\t\r]/.test(s) ? "'" + s : s;
}

// ---------------------------------------------------------------------------
// 3. Contact-value normalization. Phone normalization is DELEGATED to crm.js
//    normPhone so storage + suppression matching share one implementation.
//    isValidE164() is the stricter send-eligibility gate: normPhone stores a
//    best-effort value, but we only SEND to a well-formed +<8..15 digit> number.
//    Email is lowercased/trimmed and rejected if it contains CR/LF/control chars
//    (blocks header injection) or fails a conservative shape check.
// ---------------------------------------------------------------------------
export { normPhone };

export function isValidE164(v) {
  return typeof v === "string" && /^\+[1-9]\d{7,14}$/.test(v);
}

// Normalize for SENDING: returns a valid E.164 string or null (never junk).
export function toSendablePhone(raw) {
  const p = normPhone(raw);
  return isValidE164(p) ? p : null;
}

export function normalizeEmail(raw) {
  const s = String(raw ?? "").trim().toLowerCase();
  if (!s || s.length > 254) return null;
  if (/[\r\n\t\0]/.test(s)) return null;          // blocks header injection
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(s)) return null;
  return s;
}

// ---------------------------------------------------------------------------
// 4. Merge-field sanitization. {{name}} substitution is the top injection risk:
//    a contact whose name contains CRLF could inject email headers, one with
//    HTML could break an email body, one with a huge string could bloat an SMS
//    segment or spoof a fake "STOP" footer. Sanitize per channel BEFORE
//    substitution, and always AFTER the STOP footer is appended by the caller
//    (so a crafted name can't push the real footer past truncation).
// ---------------------------------------------------------------------------
export function safeMergeValue(v, { channel, html = false } = {}) {
  let s = String(v ?? "").replace(/[\r\n\t\0]+/g, " ").trim();
  s = channel === "sms" ? s.slice(0, 40) : s.slice(0, 120);
  return html ? esc(s) : s;
}

// Only {{name}} is supported; any unknown {{token}} is stripped, never left in
// place or reflected. For email HTML bodies pass html:true to escape the value.
export function renderTemplate(template, contact, { channel, html = false } = {}) {
  const name = safeMergeValue(contact?.name || "there", { channel, html });
  return String(template ?? "").replace(/\{\{\s*([a-zA-Z0-9_]+)\s*\}\}/g, (_, key) =>
    key === "name" ? name : ""
  );
}

// ---------------------------------------------------------------------------
// 5. SMS compliance shaping. Auto-append the STOP notice if absent (brief
//    requirement, enforced in the send path — never left to the UI). Cap absurd
//    bodies. The caller merges {{name}} AFTER this so the footer can't be pushed
//    off by a long name.
// ---------------------------------------------------------------------------
const STOP_NOTICE = "Txt STOP to opt out";
export function shapeSmsBody(body) {
  let s = String(body ?? "").slice(0, 1500);
  if (!/stop\s+to\s+opt\s+out|reply\s+stop|txt\s+stop/i.test(s)) {
    s = s.trimEnd() + " " + STOP_NOTICE;
  }
  return s;
}

// ---------------------------------------------------------------------------
// 6. Inbound SMS keyword classification. Word-boundary match on the FIRST token
//    only, so a conversational "please stop by the open house" does NOT opt out,
//    but "STOP", "stop.", "STOP ALL" do. Returns "stop" | "help" | "start" | null.
// ---------------------------------------------------------------------------
const STOP_WORDS = new Set(["stop", "stopall", "unsubscribe", "cancel", "end", "quit", "optout"]);
const HELP_WORDS = new Set(["help", "info"]);
const START_WORDS = new Set(["start", "yes", "unstop", "subscribe", "optin"]);

export function classifyInboundKeyword(text) {
  const first = String(text ?? "").trim().toLowerCase().replace(/[^a-z]+.*$/s, "");
  // handle "stop all" / "stopall" written with a space
  const collapsed = String(text ?? "").trim().toLowerCase().replace(/[^a-z]/g, "");
  if (STOP_WORDS.has(first) || collapsed === "stopall") return "stop";
  if (HELP_WORDS.has(first)) return "help";
  if (START_WORDS.has(first)) return "start";
  return null;
}

// TwiML helpers. Twilio expects a valid <Response> even when we send nothing,
// or it logs an error and may retry. escXml() the message body.
export function twimlMessage(msg) {
  return new Response(
    `<?xml version="1.0" encoding="UTF-8"?><Response><Message>${escXml(msg)}</Message></Response>`,
    { headers: { "Content-Type": "text/xml", "Cache-Control": "no-store" } }
  );
}
export function twimlEmpty() {
  return new Response(
    `<?xml version="1.0" encoding="UTF-8"?><Response></Response>`,
    { headers: { "Content-Type": "text/xml", "Cache-Control": "no-store" } }
  );
}

// ---------------------------------------------------------------------------
// 7. Quiet hours — server-side, fail-closed. Marketing SMS only 09:00–20:00
//    America/New_York. Computed with Intl (supported on modern Workers). If the
//    TZ lookup ever throws, we FAIL CLOSED (block SMS) rather than risk an
//    off-hours send. EMAIL is never subject to quiet hours.
// ---------------------------------------------------------------------------
export const QUIET_START_HOUR = 9;   // inclusive
export const QUIET_END_HOUR = 20;    // exclusive (last window is 19:xx)

export function nyHour(now = new Date()) {
  const parts = new Intl.DateTimeFormat("en-US", {
    timeZone: "America/New_York", hour: "numeric", hour12: false,
  }).formatToParts(now);
  return Number(parts.find((p) => p.type === "hour")?.value);
}

export function withinSmsQuietHours(now = new Date()) {
  try {
    const h = nyHour(now);
    if (!Number.isFinite(h)) return false; // fail closed
    return h >= QUIET_START_HOUR && h < QUIET_END_HOUR;
  } catch {
    return false; // fail closed on any Intl/TZ error
  }
}

// ---------------------------------------------------------------------------
// 8. THE consent/suppression guard. sendableRecipientsSQL is the SINGLE source
//    of truth the send pipeline (runCron) uses to pick recipients: one
//    parameterized query enforcing channel consent flag = 1, contact value
//    present, NOT in suppressions for that channel, NOT already in `sends` for
//    the campaign, and the bound tag filter. Column names come from a fixed
//    allowlist; the tag value is BOUND, never interpolated; wildcards in the tag
//    are neutralized so a tag like "a%" can't match everyone. Do not hand-roll
//    recipient selection anywhere else. LIMIT is capped to respect the Workers
//    subrequest budget (brief: chunks per cron tick, not one giant loop).
//
//    Usage (runCron):
//      const { sql, binds } = sendableRecipientsSQL(campaign, limit);
//      const rows = (await env.DB.prepare(sql).bind(...binds).all()).results;
// ---------------------------------------------------------------------------
export function sendableRecipientsSQL(campaign, limit = 50) {
  const channel = campaign.channel === "email" ? "email" : "sms";
  const consentCol = channel === "email" ? "consent_email" : "consent_sms";
  const contactCol = channel === "email" ? "email" : "phone";
  const cappedLimit = Math.max(1, Math.min(500, Number(limit) || 50));

  // Neutralize LIKE metacharacters in the (already-cleaned) tag so it can only
  // match itself, and match on a normalized ',tag,' wrapper for exact segment
  // membership. ESCAPE '\' pairs with the escaped % and _.
  const rawTag = campaign.tag_filter ? String(campaign.tag_filter).trim() : "";
  const tag = rawTag.replace(/[\\%_]/g, (c) => "\\" + c);

  // D1 uses positional `?` placeholders (index auto-increments in bind order).
  // Bind order below MUST match the ? order in the SQL exactly.
  const binds = [channel, campaign.id];      // suppressions.channel, sends.campaign_id
  let tagClause = "";
  if (rawTag) {
    tagClause = "AND (',' || REPLACE(c.tags, ' ', '') || ',') LIKE ('%,' || ? || ',%') ESCAPE '\\'";
    binds.push(tag);                          // tag
  }
  binds.push(cappedLimit);                    // limit

  const sql = `
    SELECT c.id, c.name, c.phone, c.email
    FROM contacts c
    WHERE c.${consentCol} = 1
      AND c.${contactCol} IS NOT NULL AND c.${contactCol} <> ''
      AND NOT EXISTS (
        SELECT 1 FROM suppressions s
        WHERE s.channel = ? AND s.value = c.${contactCol}
      )
      AND NOT EXISTS (
        SELECT 1 FROM sends sd
        WHERE sd.campaign_id = ? AND sd.contact_id = c.id
      )
      ${tagClause}
    ORDER BY c.id ASC
    LIMIT ?`;
  return { sql, binds, channel, contactCol };
}

// Second-line defense (TOCTOU): even after selection, re-check a single
// recipient immediately before the provider call. Catches a STOP/unsubscribe
// that landed after selection but within the same cron tick. Returns true if
// still OK to send.
export async function stillSendable(env, channel, value) {
  const ch = channel === "email" ? "email" : "sms";
  const row = await env.DB.prepare(
    "SELECT 1 FROM suppressions WHERE channel = ? AND value = ? LIMIT 1"
  ).bind(ch, value).first();
  return !row;
}

// Idempotent suppression (inbound STOP + email unsubscribe + manual). Also flips
// the matching contact's consent flag so the admin UI reflects reality. `value`
// MUST already be normalized (E.164 phone / lowercased email).
export async function suppress(env, channel, value, reason) {
  const ch = channel === "email" ? "email" : "sms";
  await env.DB.prepare(
    `INSERT INTO suppressions (channel, value, reason, ts)
     VALUES (?, ?, ?, ?)
     ON CONFLICT(channel, value) DO UPDATE SET reason = excluded.reason, ts = excluded.ts`
  ).bind(ch, value, String(reason || "").slice(0, 80), Date.now()).run();
  const col = ch === "email" ? "consent_email" : "consent_sms";
  const matchCol = ch === "email" ? "email" : "phone";
  await env.DB.prepare(
    `UPDATE contacts SET ${col} = 0 WHERE ${matchCol} = ?`
  ).bind(value).run();
}

// Remove a suppression + re-opt-in (inbound START). TCPA allows re-subscribe.
export async function unsuppress(env, channel, value) {
  const ch = channel === "email" ? "email" : "sms";
  await env.DB.prepare(
    "DELETE FROM suppressions WHERE channel = ? AND value = ?"
  ).bind(ch, value).run();
  const col = ch === "email" ? "consent_email" : "consent_sms";
  const matchCol = ch === "email" ? "email" : "phone";
  await env.DB.prepare(
    `UPDATE contacts SET ${col} = 1 WHERE ${matchCol} = ?`
  ).bind(value).run();
}

// ---------------------------------------------------------------------------
// 9. Twilio inbound signature verification. Twilio signs with HMAC-SHA1 over the
//    full request URL concatenated with the alphabetically-sorted POST params
//    (key immediately followed by value), base64-encoded, in X-Twilio-Signature.
//    Verify constant-time; reject on missing/invalid signature (403, no side
//    effects). The URL used MUST be the exact public URL Twilio called; rebuild
//    it from the trusted PUBLIC_URL secret so a spoofed Host header can't change
//    the signed string. Fails closed if TWILIO_AUTH_TOKEN is unset.
// ---------------------------------------------------------------------------
async function hmacSha1Base64(secret, msg) {
  const key = await crypto.subtle.importKey(
    "raw", new TextEncoder().encode(secret),
    { name: "HMAC", hash: "SHA-1" }, false, ["sign"]
  );
  const sig = await crypto.subtle.sign("HMAC", key, new TextEncoder().encode(msg));
  let bin = "";
  const bytes = new Uint8Array(sig);
  for (let i = 0; i < bytes.length; i++) bin += String.fromCharCode(bytes[i]);
  return btoa(bin);
}

// Build the exact URL Twilio signed from the trusted configured host, not the
// spoofable Host header. PUBLIC_URL example: https://adriancortez.com
export function twilioSignedUrl(env, url) {
  const base = String(env.PUBLIC_URL || "").replace(/\/+$/, "");
  if (!base) return url.href; // fallback; PUBLIC_URL SHOULD be set for hardening
  return base + url.pathname + (url.search || "");
}

// params: object of POSTed fields. fullUrl: from twilioSignedUrl(env, url).
export async function verifyTwilioSignature(env, fullUrl, params, signatureHeader) {
  if (!env.TWILIO_AUTH_TOKEN) return false; // fail closed
  if (!signatureHeader) return false;
  const keys = Object.keys(params).sort();
  let data = fullUrl;
  for (const k of keys) data += k + params[k];
  const expected = await hmacSha1Base64(env.TWILIO_AUTH_TOKEN, data);
  return timingSafeEqual(expected, signatureHeader);
}

// ---------------------------------------------------------------------------
// 10. Signed unsubscribe tokens for email. Format: v1.<b64url(payload)>.<sig>
//     payload = channel + ":" + value + ":" + issuedAt. Signed with UNSUB_SECRET
//     (a SEPARATE secret from ADMIN_KEY, so a leaked admin key can't forge
//     opt-out links to bulk-suppress a competitor's list, and rotating the admin
//     key doesn't invalidate every outstanding opt-out link).
//     - Bound to channel + recipient value: a token can't be replayed against a
//       different address.
//     - No attacker-controlled reflection: /u/:token only ever suppresses the
//       value embedded in the server-signed token.
//     - Suppression is already recorded on click, so token expiry is only a
//       replay bound — CAN-SPAM opt-outs are honored indefinitely regardless.
// ---------------------------------------------------------------------------
function b64url(bytesOrStr) {
  const bytes = typeof bytesOrStr === "string"
    ? new TextEncoder().encode(bytesOrStr) : bytesOrStr;
  let bin = "";
  for (let i = 0; i < bytes.length; i++) bin += String.fromCharCode(bytes[i]);
  return btoa(bin).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
}
function b64urlDecode(s) {
  s = s.replace(/-/g, "+").replace(/_/g, "/");
  while (s.length % 4) s += "=";
  const bin = atob(s);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return new TextDecoder().decode(bytes);
}

function unsubSecret(env) {
  // Prefer a dedicated secret; fall back to ADMIN_KEY only if UNSUB_SECRET is
  // unset so the feature still works pre-hardening. Document setting UNSUB_SECRET.
  return env.UNSUB_SECRET || env.ADMIN_KEY;
}

export async function makeUnsubToken(env, channel, value) {
  const ch = channel === "email" ? "email" : "sms";
  const payload = `${ch}:${value}:${Date.now()}`;
  const p = b64url(payload);
  const sig = await hmacHex(unsubSecret(env), "unsub.v1." + p);
  return `v1.${p}.${sig}`;
}

export async function verifyUnsubToken(env, token) {
  if (!token || typeof token !== "string") return null;
  const parts = token.split(".");
  if (parts.length !== 3 || parts[0] !== "v1") return null;
  const [, p, sig] = parts;
  const expect = await hmacHex(unsubSecret(env), "unsub.v1." + p);
  if (!timingSafeEqual(sig, expect)) return null;
  let payload;
  try { payload = b64urlDecode(p); } catch { return null; }
  const idx = payload.indexOf(":");
  const idx2 = payload.indexOf(":", idx + 1);
  if (idx < 1 || idx2 < 0) return null;
  const channel = payload.slice(0, idx);
  const value = payload.slice(idx + 1, idx2);
  if ((channel !== "email" && channel !== "sms") || !value) return null;
  return { channel, value };
}

// ---------------------------------------------------------------------------
// 11. Test-send guardrail. The composer's "test send to Adrian" MUST only ever
//     go to Adrian's own configured phone/email, never a UI-supplied address
//     (which would turn the admin panel into an open SMS/email relay). There is
//     NO fallback to TWILIO_FROM / EMAIL_FROM — if the target secret is unset,
//     the test is refused. Compare against ADRIAN_PHONE / ADRIAN_EMAIL.
// ---------------------------------------------------------------------------
export function assertTestTarget(env, channel, value) {
  if (channel === "email") {
    const allowed = normalizeEmail(env.ADRIAN_EMAIL);
    return !!allowed && normalizeEmail(value) === allowed;
  }
  const allowed = toSendablePhone(env.ADRIAN_PHONE);
  return !!allowed && toSendablePhone(value) === allowed;
}

// ---------------------------------------------------------------------------
// 12. Lightweight per-key rate limiter backed by KV (SITE binding), fixed
//     window. Best-effort (KV is eventually consistent): it blunts floods but is
//     NOT a hard cap — the hard cap is the cron LIMIT. Use for admin login
//     attempts, inbound webhook abuse, unsubscribe hits, and admin writes.
//     Returns true if the action is allowed. Keyed by CF-Connecting-IP where the
//     caller passes it (that header is set by Cloudflare's edge, unspoofable).
// ---------------------------------------------------------------------------
export async function rateLimit(env, key, { limit = 20, windowSec = 60 } = {}) {
  if (!env.SITE) return true; // no KV binding -> don't hard-fail the request path
  const bucket = `rl:${key}:${Math.floor(Date.now() / 1000 / windowSec)}`;
  const cur = Number((await env.SITE.get(bucket)) || 0) + 1;
  await env.SITE.put(bucket, String(cur), { expirationTtl: windowSec + 5 });
  return cur <= limit;
}

export function clientIp(req) {
  return req.headers.get("CF-Connecting-IP") || "unknown";
}

// ---------------------------------------------------------------------------
// 13. Self-test. Admin-gated GET /api/admin/marketing/security-self-test calls
//     this in staging/CI to prove the invariants hold. Returns
//     { passed, failed, errors }.
// ---------------------------------------------------------------------------
export async function runSecurityChecks(env) {
  const errors = [];
  let passed = 0;
  const ok = (label, cond) => (cond ? passed++ : errors.push(`FAIL: ${label}`));

  ok("normPhone 10-digit", normPhone("305-555-1234") === "+13055551234");
  ok("normPhone parens", normPhone("(305) 555-1234") === "+13055551234");
  ok("toSendablePhone rejects junk", toSendablePhone("not a phone") === null);
  ok("isValidE164 accepts", isValidE164("+13055551234"));
  ok("isValidE164 rejects short", !isValidE164("+1305"));

  ok("email lowercases", normalizeEmail("A@Example.COM") === "a@example.com");
  ok("email rejects CRLF", normalizeEmail("a@b.com\r\nBcc: x@y.com") === null);
  ok("email rejects bare word", normalizeEmail("notanemail") === null);

  ok("esc escapes angle", esc("<b>") === "&lt;b&gt;");
  ok("stripCsvFormula neutralizes", stripCsvFormula("=HYPERLINK(1)").startsWith("'"));
  ok("stripCsvFormula leaves plain", stripCsvFormula("Adrian") === "Adrian");

  ok("footer appended when missing", /opt out/i.test(shapeSmsBody("Hi")));
  ok("footer not duplicated", (shapeSmsBody("Hi. Reply STOP to opt out.").match(/stop/gi) || []).length === 1);

  ok("merge substitutes name", renderTemplate("Hi {{name}}", { name: "Ana" }, { channel: "sms" }) === "Hi Ana");
  ok("merge strips CRLF from name", !/[\r\n]/.test(renderTemplate("{{name}}", { name: "a\r\nb" }, { channel: "email" })));
  ok("merge drops unknown token", renderTemplate("A {{oops}} B", {}, { channel: "sms" }) === "A  B");
  ok("merge escapes html when asked", renderTemplate("{{name}}", { name: "<x>" }, { channel: "email", html: true }) === "&lt;x&gt;");

  ok("keyword STOP", classifyInboundKeyword("STOP") === "stop");
  ok("keyword stop punctuation", classifyInboundKeyword("stop.") === "stop");
  ok("keyword stop-all spaced", classifyInboundKeyword("STOP ALL") === "stop");
  ok("keyword help", classifyInboundKeyword("Help") === "help");
  ok("keyword start", classifyInboundKeyword("start") === "start");
  ok("keyword conversational not stop", classifyInboundKeyword("please stop by the open house") === null);

  ok("timingSafeEqual equal", timingSafeEqual("abc", "abc"));
  ok("timingSafeEqual unequal", !timingSafeEqual("abc", "abd"));
  ok("timingSafeEqual length mismatch", !timingSafeEqual("abc", "ab"));

  // sendableRecipientsSQL: bind count must match ? count; tag wildcards escaped
  const s1 = sendableRecipientsSQL({ id: "c1", channel: "sms" }, 50);
  ok("SQL binds match placeholders (no tag)", (s1.sql.match(/\?/g) || []).length === s1.binds.length);
  const s2 = sendableRecipientsSQL({ id: "c1", channel: "email", tag_filter: "a%_x" }, 999);
  ok("SQL binds match placeholders (tag)", (s2.sql.match(/\?/g) || []).length === s2.binds.length);
  ok("SQL escapes tag wildcards", s2.binds.some((b) => b === "a\\%\\_x"));
  ok("SQL caps limit", s2.binds[s2.binds.length - 1] === 500);

  ok("assertTestTarget refuses when unset", !assertTestTarget({}, "sms", "+13055551234"));
  ok("assertTestTarget allows own", assertTestTarget({ ADRIAN_PHONE: "3055551234" }, "sms", "+1 305 555 1234"));
  ok("assertTestTarget blocks other", !assertTestTarget({ ADRIAN_PHONE: "3055551234" }, "sms", "+13055559999"));

  // Unsub token round-trip + tamper detection (needs a secret)
  const tenv = { UNSUB_SECRET: env?.UNSUB_SECRET || "test-unsub-secret-0123456789" };
  const tok = await makeUnsubToken(tenv, "email", "a@b.com");
  const dec = await verifyUnsubToken(tenv, tok);
  ok("unsub round-trip", dec && dec.channel === "email" && dec.value === "a@b.com");
  ok("unsub tamper rejected", (await verifyUnsubToken(tenv, tok.slice(0, -2) + "xx")) === null);
  ok("unsub wrong-secret rejected", (await verifyUnsubToken({ UNSUB_SECRET: "other-secret-abcdefghij" }, tok)) === null);

  return { passed, failed: errors.length, errors };
}
=== END FILE ===

